INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-04', E'예수의 가르침과 이적 (누가복음 13장)', E'누가복음 13장', E'빌라도가 갈릴리 사람들을 학살한 사건과 실로암 망대가 무너져 사람들이 죽은 참사가 예루살렘에서 화제가 되었습니다. 당시 유대인들은 이런 비극적 사건을 당한 사람들이 특별히 더 큰 죄인이었기 때문이라고 여기는 경향이 있었습니다. 그러나 예수님께서는 이러한 인과응보적 사고를 단호히 부정하시며, 오히려 모든 사람이 회개해야 할 필요성을 강조하십니다. 이어지는 열매 없는 무화과나무 비유는 하나님의 인내하시는 사랑과 동시에 회개의 시급성을 보여줍니다. 포도원 주인은 3년 동안 열매를 기다렸고, 포도원지기의 간청으로 한 해를 더 기다리기로 합니다. 이는 하나님께서 우리에게 주시는 은혜의 시간을 의미합니다.\n\n안식일에 18년 동안 귀신 들려 꼬부라진 여인을 고치신 사건은 예수님의 권위와 자비를 동시에 보여줍니다. 회당장은 안식일 규정을 들어 비난했지만, 예수님은 "아브라함의 딸"이라는 표현으로 이 여인의 존엄성을 회복시키시며, 안식일이야말로 사탄의 속박에서 해방되기에 가장 합당한 날임을 선포하십니다. 겨자씨와 누룩의 비유를 통해 하나님 나라가 작게 시작하지만 놀랍게 성장하고 변화시키는 능력이 있음을 가르치십니다.\n\n예루살렘으로 향하시는 여정 중에 누군가 구원받을 자가 적은지 물었을 때, 예수님은 좁은 문으로 들어가기를 힘쓰라고 답하십니다. 단순히 예수님과 함께 먹고 마셨다는 외적 관계가 아니라, 진정한 회개와 믿음의 응답이 필요함을 경고하십니다. 헤롯의 위협 앞에서도 예수님은 자신의 사명을 완수하기 위해 예루살렘으로 가야 함을 분명히 하시며, 선지자들을 죽인 예루살렘을 향한 애통한 탄식으로 이 장을 마무리하십니다. 암탉이 새끼를 품듯 사랑하시지만 거부당하신 하나님의 마음이 절절히 드러납니다.', E'오늘의 핵심\n예수님은 회개의 긴급성을 강조하시면서도, 동시에 하나님의 인내하시는 사랑과 구원의 문이 열려 있음을 보여주십니다. 그러나 그 문은 좁으며, 진정한 믿음의 응답이 요구됩니다.\n\n묵상 질문\n1. 남의 불행을 그들의 죄 때문이라고 쉽게 판단하는 내 모습은 없나요?\n2. 하나님께서 내게 주신 은혜의 시간 동안 나는 어떤 열매를 맺고 있나요?\n3. 예수님을 아는 것과 예수님께 알려지는 것의 차이는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-05', E'약자를 위한 배려 (누가복음 14장)', E'누가복음 14장', E'안식일에 바리새인 지도자의 집에서 벌어진 일은 예수님의 하나님 나라 가치관을 선명하게 보여줍니다. 수종병 든 사람을 고치시는 것으로 시작된 이 날의 가르침은, 당시 종교 지도자들이 붙잡혀 있던 형식주의와 위선을 드러내고 있습니다. 예수님께서는 "너희 중에 누가 그 아들이나 소가 우물에 빠졌으면 안식일에라도 곧 끌어내지 않겠느냐"(눅 14:5)고 물으시며, 생명을 살리는 일이 종교적 규정보다 우선됨을 가르쳐 주십니다.\n\n이어지는 잔치의 비유들은 하나님 나라의 역설적 질서를 보여줍니다. 높은 자리를 탐하는 이들에게 예수님께서는 스스로 낮은 자리를 택하라고 가르치십니다. 더 나아가 잔치를 베풀 때는 갚을 능력이 없는 가난한 자들과 몸 불편한 자들을 청하라고 말씀하십니다. 이는 단순한 예의범절을 넘어서는 하나님 나라의 근본 원리를 담고 있습니다. 하나님의 은혜는 대가를 바라지 않는 무조건적 사랑에서 흘러나오기 때문입니다.\n\n큰 잔치 비유는 하나님의 구원 초청에 대한 인간의 반응을 날카롭게 묘사합니다. 초청받은 이들은 밭, 소, 결혼 등 세상일을 핑계로 잔치 참여를 거부합니다. 그러자 주인은 거리의 가난한 자들과 장애인들을 데려오라고 명령합니다. 이는 유대인들이 거부한 복음이 이방인과 소외된 이들에게로 향하게 될 것을 암시합니다. \n\n마지막으로 예수님께서는 제자도의 값비싼 대가를 분명히 하십니다. 가족보다 예수님을 더 사랑하고, 자기 십자가를 지며, 모든 소유를 버릴 각오가 되어 있어야 한다고 말씀하십니다. 이는 무모한 열정이 아니라 신중한 헌신을 요구하는 것입니다. 망대를 세우거나 전쟁을 치르기 전에 계산하듯, 제자가 되기로 결심하기 전에 그 대가를 깊이 생각해야 합니다. 맛을 잃은 소금이 버려지듯, 중도에 포기하는 것보다는 처음부터 신중하게 결단하는 것이 중요함을 가르쳐 주십니다.', E'오늘의 핵심\n예수님께서는 안식일 논쟁과 잔치 비유를 통해 하나님 나라의 역설적 질서를 보여주시며, 참된 제자도는 모든 것을 버릴 각오와 함께하는 신중한 헌신임을 가르치십니다.\n\n묵상 질문\n1. 종교적 형식보다 생명과 사랑을 우선시하는 예수님의 가르침을 내 삶에서 어떻게 실천할 수 있을까요?\n2. 대가를 바라지 않고 베푸는 사랑을 실천하기 어려운 이유는 무엇일까요?\n3. 예수님의 제자가 되기 위해 내가 버려야 할 것과 감당해야 할 십자가는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-07', E'약자를 위한 배려 (누가복음 15장)', E'누가복음 15장', E'세리와 죄인들이 예수님의 말씀을 듣기 위해 가까이 나아오자, 바리새인과 서기관들은 예수님이 죄인들과 함께 식사하신다며 수군거렸습니다. 당시 유대 사회에서 세리와 죄인들은 하나님의 백성 공동체에서 배제된 사람들이었기에, 종교 지도자들은 예수님의 행동을 이해할 수 없었습니다. 이에 예수님께서는 세 가지 비유를 통해 잃어버린 자를 향한 하나님의 마음을 보여주십니다.\n\n잃은 양의 비유에서 목자는 아흔아홉 마리를 들에 두고 한 마리를 찾아 나섭니다. 잃은 드라크마의 비유에서 여인은 등불을 켜고 집을 쓸며 부지런히 동전 하나를 찾습니다. 이 두 비유는 하나님께서 잃어버린 한 영혼을 얼마나 소중히 여기시는지를 보여줍니다. 특히 찾은 후의 기쁨을 이웃과 함께 나누는 모습은 "죄인 한 사람이 회개하면 하늘에서는 회개할 것 없는 의인 아흔아홉으로 말미암아 기뻐하는 것보다 더하리라"(눅 15:7)는 말씀으로 이어집니다.\n\n탕자의 비유는 더욱 깊은 차원의 하나님 사랑을 보여줍니다. 아버지의 재산을 탕진하고 돼지치기로 전락한 둘째 아들이 돌아오자, 아버지는 거리가 먼데도 달려가 목을 안고 입을 맞춥니다. 가장 좋은 옷과 가락지, 신발을 주고 잔치를 베푸는 아버지의 모습은 회개하는 죄인을 향한 하나님의 무조건적인 사랑을 보여줍니다. 맏아들의 불평에도 아버지는 "네 동생은 죽었다가 살아났으며 내가 잃었다가 얻었기로 우리가 즐거워하고 기뻐하는 것이 마땅하다"고 말씀합니다. 이는 바리새인들처럼 자신의 의로움에 갇혀 하나님의 은혜를 이해하지 못하는 이들을 향한 초청이기도 합니다.', E'오늘의 핵심\n예수님께서는 세 가지 비유를 통해 잃어버린 한 영혼을 찾아 구원하시는 하나님의 열정적인 사랑과 회개하는 죄인을 맞이하시는 하나님의 무조건적인 은혜를 보여주십니다.\n\n묵상 질문\n1. 나는 혹시 맏아들처럼 하나님의 은혜보다 내 의로움에 갇혀 있지는 않나요?\n2. 하나님께서 나를 찾아 구원하신 그 사랑을 깊이 묵상해 보셨나요?\n3. 내 주변의 잃어버린 영혼들을 향한 하나님의 마음을 품고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-08', E'약자를 위한 배려 (누가복음 16장)', E'누가복음 16장', E'누가복음 16장은 물질을 대하는 제자의 자세와 영원한 생명의 문제를 깊이 있게 다루고 있습니다. 예수님께서는 먼저 불의한 청지기의 비유를 통해 우리에게 지혜로운 청지기직에 대해 가르치십니다. 이 청지기는 해고 통보를 받자 미래를 대비해 주인에게 빚진 자들의 빚을 탕감해 주는 기지를 발휘합니다. 주인은 오히려 그의 지혜로운 처신을 칭찬했는데, 이는 그가 위기 상황에서 미래를 준비하는 통찰력을 보였기 때문입니다. 예수님은 이를 통해 "불의의 재물로 친구를 사귀라"(눅 16:9)고 가르치시는데, 이는 우리가 가진 물질을 영원한 관점에서 사용하라는 뜻입니다. \n\n작은 것에 충성된 자가 큰 것에도 충성될 수 있다는 가르침은 일상의 물질 관리가 곧 영적 성숙도와 연결됨을 보여줍니다. 우리는 하나님과 재물을 겸하여 섬길 수 없으며, 둘 중 하나를 선택해야 합니다. 돈을 사랑하던 바리새인들이 이 가르침을 비웃자, 예수님은 사람 앞에서 높임받는 것이 하나님 앞에서는 미움받을 수 있음을 경고하십니다.\n\n이어지는 부자와 나사로의 이야기는 물질주의의 결말을 극명하게 보여줍니다. 호화롭게 살던 부자는 자기 대문 앞의 거지 나사로를 외면했고, 죽음 후에는 그들의 운명이 완전히 뒤바뀝니다. 음부에서 고통받는 부자와 아브라함의 품에서 위로받는 나사로의 모습은 현세의 삶이 영원을 결정함을 보여줍니다. 부자가 뒤늦게 형제들에게라도 경고하고자 했지만, 아브라함은 이미 주어진 말씀에 순종하지 않는 자들은 기적을 보아도 믿지 않을 것임을 일깨워줍니다. 하나님의 나라는 물질의 풍요가 아닌 하나님의 말씀에 대한 순종과 이웃 사랑의 실천으로 이루어집니다.', E'오늘의 핵심\n예수님은 우리가 맡은 물질을 영원한 관점에서 지혜롭게 사용하며, 작은 일에 충성함으로써 하나님 나라의 참된 부요함을 누리도록 가르치십니다.\n\n묵상 질문\n1. 나는 물질을 영원을 위해 사용하고 있나요, 아니면 현재의 안락함만을 위해 사용하고 있나요?\n2. 내 주변의 ''나사로''를 외면하고 있지는 않은지 돌아볼 수 있을까요?\n3. 작은 일상의 충성이 어떻게 영적 성장으로 이어질지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-09', E'약자를 위한 배려 (누가복음 17장)', E'누가복음 17장', E'예수님께서는 예루살렘으로 향하시는 길에서 제자들에게 공동체의 삶과 하나님 나라의 본질에 관한 중요한 가르침을 주십니다. 먼저 실족하게 하는 일의 심각성을 경고하시면서, 특히 믿음이 연약한 자들을 넘어뜨리는 것이 얼마나 큰 죄인지를 강조하십니다. 동시에 형제가 죄를 지었을 때 경고하되, 회개하면 하루에 일곱 번이라도 용서하라는 놀라운 은혜의 원리를 제시하십니다. \n\n이런 가르침에 부담을 느낀 제자들이 "우리에게 믿음을 더하소서"라고 간구하자, 예수님께서는 겨자씨만한 작은 믿음이라도 있다면 불가능해 보이는 일도 가능하다고 말씀하십니다. 그러나 곧이어 종의 비유를 통해 우리가 하나님 앞에서는 무익한 종에 불과하며, 마땅히 해야 할 일을 했을 뿐임을 깨우쳐 주십니다.\n\n사마리아와 갈릴리 사이를 지나시던 예수님께서 열 명의 나병환자를 만나 고쳐주신 사건은 감사와 믿음의 본질을 보여줍니다. 유대인이 아닌 사마리아 사람만이 돌아와 감사를 표현했다는 사실은, 하나님의 은혜가 민족과 신분의 경계를 넘어선다는 것을 분명히 드러냅니다. "네 믿음이 너를 구원하였느니라"는 예수님의 선언은 단순한 육체의 치유를 넘어 전인적 구원을 의미합니다.\n\n바리새인들이 하나님 나라가 언제 임하는지 묻자, 예수님께서는 하나님의 나라는 눈에 보이는 방식으로 오는 것이 아니라 "너희 안에 있느니라"고 말씀하십니다. 이는 하나님의 나라가 예수님 자신과 함께 이미 그들 가운데 임했음을 의미합니다. 마지막으로 재림의 날에 대해 말씀하시면서, 노아와 롯의 시대처럼 사람들이 일상에 매여 있다가 갑작스럽게 심판을 맞게 될 것을 경고하십니다. 그날에는 세상의 것에 미련을 두지 말고, 자기 목숨을 보전하려는 자는 오히려 잃을 것이라는 역설적 진리를 가르치십니다.', E'오늘의 핵심\n예수님께서는 공동체 안에서의 용서와 섬김, 감사하는 믿음, 그리고 이미 임했으나 아직 완성되지 않은 하나님 나라의 긴장 속에서 깨어 있는 삶을 살라고 가르치십니다.\n\n묵상 질문\n1. 나는 연약한 믿음의 형제자매들을 실족하게 하지는 않았는지, 또한 용서를 아끼고 있지는 않은지 돌아볼 수 있을까요?\n2. 하나님의 은혜를 받고도 감사를 잊고 살아가는 아홉 명의 나병환자처럼 살고 있지는 않나요?\n3. 하나님의 나라가 내 안에 있다는 말씀이 오늘 내 삶에 어떤 의미가 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-10', E'약자를 위한 배려 (누가복음 18장)', E'누가복음 18장', E'예수님께서는 예루살렘으로 향하는 길에서 제자들과 무리들에게 하나님 나라의 본질을 가르치셨습니다. 누가복음 18장은 기도와 겸손, 그리고 참된 믿음이 무엇인지를 보여주는 귀한 가르침들로 가득합니다.\n\n먼저 예수님은 불의한 재판관과 과부의 비유를 통해 낙심하지 않고 항상 기도해야 함을 가르치십니다. 하나님을 두려워하지 않고 사람을 무시하는 재판관조차 끈질긴 간구에는 응답했는데, 하물며 사랑의 하나님께서 당신의 백성들의 간절한 기도를 외면하시겠느냐는 것입니다. 이어지는 바리새인과 세리의 기도 비유는 하나님께서 받으시는 기도가 어떤 것인지 명확히 보여줍니다. 자신의 의로움을 자랑하며 다른 이를 멸시하는 바리새인의 기도와 달리, "하나님이여 불쌍히 여기소서 나는 죄인이로소이다"(눅 18:13)라는 세리의 겸손한 고백이 하나님께 의롭다 함을 받았습니다.\n\n예수님은 어린아이들을 축복하시며 하나님 나라는 이런 자의 것이라 선언하십니다. 제자들이 어린아이들을 꾸짖었지만, 예수님은 오히려 그들을 가까이 부르셨습니다. 이는 하나님 나라가 지위나 능력이 아닌 순전한 믿음과 겸손함으로 받아들이는 자들의 것임을 보여줍니다. \n\n부유한 관리와의 만남은 영생을 얻는 길이 단순히 계명을 지키는 것을 넘어 예수님을 온전히 따르는 것임을 드러냅니다. 어려서부터 계명을 다 지켰다는 그에게 예수님은 모든 것을 팔아 가난한 자들에게 나누어주고 당신을 따르라 하셨지만, 큰 부자였던 그는 근심하며 떠났습니다. 이는 재물이 하나님보다 우선순위가 될 때 영생의 길을 가로막는 장애물이 됨을 보여줍니다.\n\n마지막으로 여리고 성 밖의 맹인은 예수님을 "다윗의 자손"으로 부르며 간절히 도움을 청했습니다. 사람들의 제지에도 불구하고 더욱 크게 부르짖는 그의 믿음을 보시고, 예수님은 "네 믿음이 너를 구원하였느니라"고 선언하시며 그의 눈을 뜨게 하셨습니다. 이처럼 누가복음 18장은 하나님께서 기뻐하시는 것이 교만한 자의 업적이 아니라 겸손한 자의 믿음임을 분명히 보여줍니다.', E'오늘의 핵심\n하나님께서는 자신의 의로움을 내세우는 교만한 마음이 아니라, 전적으로 하나님의 은혜를 구하는 겸손하고 간절한 믿음을 기뻐하십니다.\n\n묵상 질문\n1. 나의 기도가 하나님께 간구하는 것보다 나의 의로움을 드러내는 데 치중하고 있지는 않은가요?\n2. 어린아이처럼 순전한 마음으로 하나님 나라를 받아들이는 것을 방해하는 것은 무엇일까요?\n3. 여리고의 맹인처럼 절박한 마음으로 예수님을 부르짖어 본 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-11', E'약자를 위한 배려 (누가복음 19장)', E'누가복음 19장', E'여리고 성으로 들어가시는 예수님 앞에는 한 작은 남자가 있었습니다. 삭개오는 로마 제국을 위해 일하는 세리장으로서 경제적으로는 부유했지만, 동족들로부터는 철저히 배척당하는 외로운 사람이었습니다. 그런 그가 예수님에 대한 소문을 듣고 그분이 어떤 분인지 보고자 하는 마음으로 돌무화과나무에 올라갔다는 것은, 단순한 호기심을 넘어선 영적 갈망의 표현이었습니다.\n\n예수님께서는 나무 위의 삭개오를 보시고 "삭개오야 속히 내려오라 내가 오늘 네 집에 유하여야 하겠다"(눅 19:5)고 말씀하십니다. 주변 사람들이 죄인의 집에 들어간다며 수군거렸지만, 예수님의 관심은 오직 잃어버린 한 영혼을 구원하시는 데 있었습니다. 주님의 사랑을 경험한 삭개오는 즉시 자신의 재산 절반을 가난한 자들에게 나누고 부당하게 취한 것은 네 배로 갚겠다고 선언합니다. 이것이 바로 구원받은 자의 변화된 삶의 모습입니다.\n\n이어지는 므나 비유는 주님께서 맡기신 것을 어떻게 관리해야 하는지를 가르쳐줍니다. 충성된 종들은 맡은 것을 잘 활용하여 열매를 맺었지만, 한 종은 주인을 오해하고 두려워하여 아무것도 하지 않았습니다. 하나님의 은혜는 우리가 감사함으로 응답하고 충성스럽게 사용할 때 더욱 풍성해집니다.\n\n예루살렘에 입성하시는 예수님의 모습은 겸손한 왕의 모습으로 나타납니다. 제자들과 무리가 환호했지만, 예수님께서는 도리어 예루살렘을 보시며 우셨습니다. 구원의 때를 알지 못하는 백성들을 향한 주님의 애통함이 드러나는 장면입니다. 성전에서 장사하는 자들을 내쫓으시며 "내 집은 기도하는 집"이라고 선포하신 것은, 종교가 형식과 이익추구로 변질되었을 때 하나님께서 얼마나 슬퍼하시는지를 보여줍니다.', E'오늘의 핵심\n예수님께서는 세상에서 소외된 삭개오를 찾아 구원하시고, 예루살렘을 향해 우시며, 기도의 집이 되어야 할 성전을 정화하심으로써 잃어버린 영혼과 잃어버린 예배를 회복시키십니다.\n\n묵상 질문\n1. 나는 삭개오처럼 예수님을 간절히 만나고자 하는 영적 갈망을 가지고 있나요?\n2. 주님께서 내게 맡기신 은사와 사명을 충성스럽게 사용하고 있나요?\n3. 내 삶과 예배가 진정한 기도와 헌신으로 채워져 있나요, 아니면 형식과 이익추구로 변질되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-12', E'약자를 위한 배려 (누가복음 20장)', E'누가복음 20장', E'예루살렘에 입성하신 예수님께서는 성전에서 백성들을 가르치며 복음을 전하셨습니다. 그러자 종교 지도자들이 몰려와 예수님의 권위에 대해 따져 묻습니다. 예수님께서는 요한의 세례가 어디로부터 왔는지 되물으심으로써 그들의 위선을 드러내셨습니다. 진리보다는 자신들의 체면과 안위만을 생각하는 그들의 모습이 여실히 나타납니다.\n\n이어서 예수님께서는 악한 농부들의 비유를 통해 하나님의 마음을 보여주십니다. 포도원 주인이 보낸 종들을 때리고 능욕하며, 마침내 사랑하는 아들마저 죽이는 농부들의 모습은 선지자들과 하나님의 아들을 거부하는 이스라엘의 역사를 압축적으로 보여줍니다. "건축자들의 버린 돌이 모퉁이의 머릿돌이 되었느니라"(눅 20:17)는 말씀은 십자가에서 버림받으실 예수님께서 결국 구원의 기초가 되실 것을 예언하고 있습니다.\n\n종교 지도자들은 예수님을 함정에 빠뜨리려고 가이사에게 세금을 바치는 문제로 시험합니다. 그러나 예수님께서는 "가이사의 것은 가이사에게, 하나님의 것은 하나님께 바치라"는 지혜로운 답변으로 그들을 침묵시키셨습니다. 이는 단순히 정치적 문제를 회피하신 것이 아니라, 우리가 하나님의 형상으로 지음받은 존재로서 온전히 하나님께 속해야 함을 가르치신 것입니다.\n\n부활을 부인하는 사두개인들의 질문에 예수님께서는 하나님이 "죽은 자의 하나님이 아니요 살아 있는 자의 하나님"이심을 선포하십니다. 아브라함과 이삭과 야곱이 여전히 하나님 앞에 살아 있다는 이 말씀은 영원한 생명에 대한 확실한 소망을 우리에게 심어줍니다. 예수님께서는 종교적 권위를 내세우며 교만하게 행동하는 서기관들을 경계하시며, 진정한 신앙은 겸손과 섬김에 있음을 가르치셨습니다.', E'오늘의 핵심\n예수님께서는 종교 지도자들의 도전 앞에서 하나님의 권위와 진리를 선포하시며, 참된 신앙은 하나님과 이웃을 향한 겸손한 섬김에 있음을 가르치십니다.\n\n묵상 질문\n1. 나는 하나님의 진리보다 사람들의 시선과 체면을 더 의식하며 살고 있지는 않나요?\n2. 하나님의 형상으로 지음받은 나 자신을 온전히 하나님께 드리고 있나요?\n3. 부활의 소망을 품고 영원한 생명의 관점에서 오늘을 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-14', E'영광과 평화로의 초대 (누가복음 22장)', E'누가복음 22장', E'유월절이라 하는 무교절이 다가오는 때, 예루살렘은 긴장감으로 가득했습니다. 대제사장들과 서기관들이 예수를 제거할 방법을 찾고 있었고, 열두 제자 중 하나인 유다에게 사탄이 들어가 배신의 씨앗이 뿌려졌습니다. 이런 어두운 기운이 감도는 가운데서도 예수님은 제자들과 함께 유월절 만찬을 준비하십니다.\n\n"내가 고난을 받기 전에 너희와 함께 이 유월절 먹기를 원하고 원하였노라"(눅 22:15)는 예수님의 말씀에서 제자들을 향한 깊은 사랑이 묻어납니다. 1400년간 이어져 온 유월절이 이제 새로운 의미로 전환되는 순간이었습니다. 떡을 떼시며 ''너희를 위하여 주는 내 몸''이라 하시고, 잔을 드시며 ''내 피로 세우는 새 언약''이라 선포하십니다. 구약의 유월절 어린 양이 참된 유월절 어린 양이신 예수님 자신을 가리키고 있었음을 보여주신 것입니다.\n\n그러나 이 거룩한 식탁에서조차 제자들은 누가 더 큰지를 놓고 다투었습니다. 예수님은 이들에게 섬김의 리더십을 가르치시며 "나는 섬기는 자로 너희 중에 있노라"고 말씀하십니다. 권력과 지위를 추구하는 세상의 방식과는 전혀 다른 하나님 나라의 질서를 보여주신 것입니다.\n\n감람산에서의 기도는 예수님의 인성과 신성이 가장 극명하게 드러나는 장면입니다. 땀이 핏방울같이 떨어질 정도로 고뇌하시면서도 "내 원대로 마시옵고 아버지의 원대로 되기를 원하나이다"라고 순종하십니다. 하나님의 뜻에 자신을 완전히 내어드리는 것이 얼마나 고통스러운지, 그러나 그것이 진정한 믿음의 길임을 보여주십니다.\n\n베드로의 부인은 우리 모두의 연약함을 대변합니다. 주와 함께 죽을 각오까지 했던 그가 한 여종 앞에서조차 예수님을 모른다고 부인합니다. 그러나 예수님은 이미 베드로의 실패를 아시고도 그의 믿음이 떨어지지 않기를 기도하셨습니다. 우리의 연약함보다 더 크신 주님의 사랑과 은혜가 여기에 있습니다.', E'오늘의 핵심\n예수님은 다가올 십자가의 고난을 아시면서도 제자들과의 마지막 만찬을 간절히 원하셨고, 새 언약의 의미를 가르치시며 끝까지 하나님의 뜻에 순종하는 모범을 보이셨습니다.\n\n묵상 질문\n1. 예수님이 제자들과의 마지막 식사를 그토록 간절히 원하신 이유는 무엇일까요?\n2. 내 삶에서 ''내 원대로''가 아닌 ''아버지의 원대로''를 선택해야 할 영역은 무엇인가요?\n3. 연약함 속에서도 나를 위해 기도하시는 예수님의 사랑을 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-15', E'영광과 평화로의 초대 (누가복음 23장)', E'누가복음 23장', E'누가복음 23장은 예수님께서 빌라도와 헤롯 앞에서 재판받으시고, 십자가에 달려 돌아가시는 과정을 보여줍니다. 이 장면들은 인간의 불의와 하나님의 의가 극명하게 대비되는 순간입니다.\n\n빌라도는 예수님에게서 아무 죄도 찾을 수 없다고 세 번이나 선언했습니다. 헤롯 역시 예수님께 죽을 죄가 없음을 인정했습니다. 그러나 군중의 압력 앞에서 빌라도는 결국 진리를 포기하고 불의한 판결을 내립니다. 민란과 살인죄로 갇혀 있던 바라바는 풀려나고, 아무 죄 없으신 예수님은 십자가를 지게 되었습니다. 이는 단순한 사법적 오판이 아니라, 죄인이 의인을 대신하여 심판받는 구원의 신비를 보여주는 장면입니다.\n\n십자가의 길에서 예수님은 자신을 위해 우는 여인들에게 "나를 위하여 울지 말고 너희와 너희 자녀를 위하여 울라"고 말씀하십니다. 자신의 고난 중에도 예루살렘의 미래를 염려하시는 예수님의 모습에서 우리는 참된 목자의 마음을 봅니다. \n\n십자가 위에서 예수님은 "아버지 저들을 사하여 주옵소서 자기들이 하는 것을 알지 못함이니이다"라고 기도하셨습니다. 자신을 조롱하고 못 박는 이들을 위해 용서를 구하시는 이 기도는 하나님 사랑의 극치를 보여줍니다. 함께 달린 두 강도 중 한 사람은 끝까지 예수님을 조롱했지만, 다른 한 사람은 자신의 죄를 인정하고 예수님께 구원을 간구했습니다. 예수님은 그에게 "오늘 네가 나와 함께 낙원에 있으리라"고 약속하셨습니다.\n\n정오부터 오후 3시까지 온 땅에 어둠이 임했고, 성소의 휘장이 찢어졌습니다. 이는 예수님의 죽으심으로 하나님과 인간 사이의 막힌 담이 허물어졌음을 상징합니다. 예수님을 처형한 백부장조차 "이 사람은 정녕 의인이었도다"라고 고백했습니다. 아리마대 요셉은 용기를 내어 예수님의 시신을 거두어 장사지냈습니다.\n\n누가복음 23장은 우리에게 십자가의 역설을 보여줍니다. 가장 불의한 재판이 가장 의로운 구원을 이루었고, 가장 큰 고난이 가장 큰 사랑을 드러냈습니다. 오늘도 우리는 이 십자가 앞에서 우리의 죄를 고백하고, 그 사랑에 감사하며, 용서의 능력을 경험하게 됩니다.', E'오늘의 핵심\n예수님은 불의한 재판과 십자가의 고난 속에서도 용서와 구원의 사랑을 보여주셨고, 그 죽으심으로 하나님과 우리 사이의 막힌 담을 허무셨습니다.\n\n묵상 질문\n1. 빌라도처럼 진리를 알면서도 타협하고 있는 내 삶의 영역은 어디입니까?\n2. 십자가 위에서도 용서를 구하신 예수님의 사랑이 내게는 어떤 의미로 다가옵니까?\n3. 오늘 내가 용서해야 할 사람이나 화해해야 할 관계는 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-16', E'영광과 평화로의 초대 (누가복음 24장)', E'누가복음 24장', E'안식일 다음 날 이른 새벽, 여인들이 향품을 들고 무덤을 찾았을 때 돌이 이미 굴려져 있었고 예수님의 시체는 보이지 않았습니다. 당황한 그들에게 천사가 나타나 "어찌하여 살아 있는 자를 죽은 자 가운데서 찾느냐"(눅 24:5)고 물으며 예수님의 부활을 알렸습니다. 갈릴리에서 미리 말씀하신 대로 사흘 만에 다시 살아나신 것입니다.\n\n이 놀라운 소식을 들은 제자들의 반응은 의외로 냉담했습니다. 여인들의 증언을 "허탄한 듯이" 여기며 믿지 않았던 것입니다. 베드로만이 무덤으로 달려가 빈 무덤을 확인했지만, 그마저도 놀라워하며 집으로 돌아갔을 뿐입니다. 부활의 첫 증인들과 첫 청중들 사이에는 이렇게 깊은 간극이 존재했습니다.\n\n그날 엠마오로 가던 두 제자의 모습은 더욱 애잔합니다. 예수님이 이스라엘을 구원할 메시아라고 믿었던 그들의 희망은 십자가 사건으로 완전히 무너져 있었습니다. 부활하신 예수님이 곁에서 동행하며 말씀을 풀어주셨지만, 그들의 눈은 여전히 가려져 있었습니다. 저녁 식사 자리에서 떡을 떼시는 순간에야 비로소 눈이 열려 주님을 알아보았으나, 예수님은 이미 사라지신 후였습니다.\n\n예루살렘으로 돌아온 제자들에게 부활하신 예수님이 다시 나타나셨습니다. 두려워하는 제자들에게 손과 발의 못 자국을 보이시고, 구운 생선까지 잡수시며 육체의 부활을 증명하셨습니다. 그리고 모세와 선지자들의 글에서부터 시작하여 구약 전체에 기록된 메시아의 고난과 부활이 어떻게 성취되었는지 설명해 주셨습니다.\n\n부활의 주님은 단순히 죽음을 이기신 것에 그치지 않으셨습니다. 의심하고 두려워하는 제자들을 찾아오셔서 그들의 닫힌 마음을 열어주시고, 성경을 깨닫게 하시며, "이 모든 일의 증인"이 되라는 새로운 사명을 부여하셨습니다. 실패와 좌절로 무너진 이들이 부활의 증인으로 다시 세워지는 놀라운 회복의 역사가 일어난 것입니다.', E'오늘의 핵심\n부활하신 예수님은 의심하고 두려워하는 제자들에게 직접 나타나셔서 성경을 깨닫게 하시고, 그들을 부활의 증인으로 세우십니다.\n\n묵상 질문\n1. 내가 부활의 소식을 "허탄한 듯이" 여기며 의심했던 때는 언제였나요?\n2. 엠마오 제자들처럼 주님이 동행하시는데도 알아보지 못한 경험이 있으신가요?\n3. 부활의 증인으로 살아가기 위해 오늘 내게 필요한 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-17', E'들러리의 기쁨', E'요한복음 3장', E'예수님께서 오시기 전 예수님의 오실 길을 준비한 이가 바로 세례 요한입니다. 세례 요한은 말라기 선지자 이후 4백여 년간 이어졌던 침묵을 깨고 등장한 사람입니다. 그는 회개하라는 메시지를 선포합니다. 예수님께서는 세례 요한에게 세례를 받으시고, 40일간 광야에서 금식기도를 마치신 후, 마귀의 시험을 물리치셨습니다. 그리고 공생애를 시작하셨습니다. 그 후 세례 요한은 헤롯에 의해 죽임을 당하고 맙니다. 예수의 길을 예비하며 들러리의 기쁨을 누리며 살았던 세례 요한은 짧지만 소중한 사역을 감당하고 죽은 것입니다.\n세례 요한이 죽고 난 후, 예수님께서는 제자들과 함께 갈릴리 가나의 혼인식에 참석하십니다. 이때 예수님께서는 물이 변하여 포도주가 되게 하는 기적을 베푸십니다. 이 기적은 예수님께서 베푸신 첫 표적이었습니다. 유월절이 가깝자 예수님께서는 예루살렘을 방문하셔서 성전을 찾으십니다. 예수님께서는 그곳에서 장사하는 사람들을 내쫓으시고, 성전을 정결하게 하십니다. 유대인들이 "네가 이런 일을 행하니 무슨 표적을 우리에게 보이겠느냐"(요 2:18)라고 시비합니다. 이에 예수님께서는 헐린 성전을 사흘 만에 일으키리라는 말씀으로, 장차 있을 일을 말씀하십니다.', E'오늘의 핵심\n인생들의 빛이 되시는 예수님이 이 땅에 오셔서 인류 구원의 사역을 시작하시고, 세례 요한은 그분의 오실 길을 기쁨으로 준비합니다.\n\n묵상 질문\n1. 주님의 길을 예비하는 일에서 기쁨을 느꼈던 세례 요한을 보며, 하나님은 어떤 마음으로 우리를 사용하고 싶으신 걸까요?\n2. 내 삶에서 남들에게 주목받지 않아도 기꺼이 감당할 수 있는 사역이 있나요?\n3. 세례 요한처럼 주님을 높이고 준비하는 역할에 진심으로 기쁨을 느낄 수 있도록 기도해 보겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-18', E'영원한 생명수이신 예수 (요한복음 4장)', E'요한복음 4장', E'예수님은 유대인이라면 피해 갔을 사마리아 땅을 "통과하여야 하겠는지라"고 말씀하십니다. 이것은 단순한 지리적 경로가 아닌, 한 영혼을 향한 하나님의 구원 계획이었습니다. 정오의 뜨거운 햇볕 아래 홀로 물을 길으러 온 여인, 사람들의 시선을 피해야 했던 그녀에게 예수님은 먼저 다가가십니다. "물을 좀 달라." 모든 것을 주실 수 있는 분이 오히려 목마른 나그네가 되어 구하시는 이 장면은 놀라운 은혜의 시작입니다.\n\n여인은 유대인과 사마리아인 사이의 민족적 장벽을 먼저 언급하지만, 예수님은 전혀 다른 차원의 대화로 이끄십니다. "내가 주는 물을 마시는 자는 영원히 목마르지 아니하리니"(요 4:14). 야곱의 우물에서 나오는 물과는 비교할 수 없는 생명의 물, 그것은 인간의 가장 깊은 갈증을 해결하는 영원한 샘물입니다. 예수님은 여인의 삶의 아픔 - 다섯 번의 결혼 실패와 현재의 불안정한 관계까지 모두 아시면서도, 정죄하지 않으시고 오히려 참된 예배자의 길로 인도하십니다.\n\n가장 인상적인 전환은 여인이 물동이를 버려두고 동네로 달려간 장면입니다. 매일 필요했던 물동이보다 더 중요한 것을 발견한 것입니다. "내가 행한 모든 일을 내게 말한 사람을 와서 보라"는 그녀의 외침은 수치와 소외의 삶에서 벗어난 해방의 선언이었습니다. 한 여인의 변화는 온 마을의 구원으로 이어집니다. 사마리아인들이 예수님을 "참으로 세상의 구주"로 고백하게 된 것입니다.\n\n같은 장에서 왕의 신하가 보여준 믿음도 주목할 만합니다. 죽어가는 아들을 위해 애타게 구했던 그는 예수님의 "네 아들이 살아 있다"는 말씀만을 믿고 돌아갑니다. 그 믿음의 발걸음은 온 집안의 구원으로 이어졌습니다. 요한복음 4장은 민족과 신분, 과거의 상처를 뛰어넘는 예수님의 구원이 얼마나 포괄적이고 완전한지를 보여줍니다.', E'오늘의 핵심\n예수님은 유대인과 사마리아인의 장벽을 넘어, 한 여인의 영혼의 목마름을 영원한 생수로 채우시고, 온 마을을 구원으로 인도하십니다.\n\n묵상 질문\n1. 내 삶의 어떤 목마름을 세상의 우물물로 채우려 하고 있나요?\n2. 예수님께서 내 삶의 아픔과 과거를 다 아시면서도 여전히 사랑하신다는 사실이 내게 어떤 위로가 되나요?\n3. 사마리아 여인처럼 물동이를 버려두고 달려가 전할 만한 예수님과의 만남이 내게도 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-19', E'영원한 생명수이신 예수 (요한복음 5장)', E'요한복음 5장', E'베데스다 연못가에는 기적을 바라는 수많은 병자들이 모여 있었습니다. 물이 움직일 때 가장 먼저 들어가는 자가 나음을 받는다는 전설을 붙잡고, 그들은 매일같이 그곳에 누워있었습니다. 그중에서도 38년 된 병자는 가장 절망적인 상황에 있었습니다. 그에게는 물이 움직일 때 연못에 넣어줄 사람조차 없었기 때문입니다. 예수님은 바로 그를 찾아가셨습니다. "네가 낫고자 하느냐"는 예수님의 질문에 그는 자신의 불가능을 토로할 뿐이었지만, 예수님은 단호히 명령하십니다. "일어나 네 자리를 들고 걸어가라." 38년의 무력함이 한순간에 생명의 능력으로 바뀌는 놀라운 기적이 일어났습니다.\n\n그러나 종교 지도자들의 시선은 달랐습니다. 그들에게는 38년 만에 걸어가는 한 인간의 기쁨보다 안식일 규정이 더 중요했습니다. 자리를 들고 가는 것이 안식일을 범하는 일이라고 정죄하는 그들 앞에서, 예수님은 놀라운 선언을 하십니다. "내 아버지께서 이제까지 일하시니 나도 일한다." 하나님께서는 안식일에도 생명을 살리시고 은혜를 베푸시는 분이심을 보여주신 것입니다. 더 나아가 예수님은 자신이 생명을 주시는 권세와 심판하는 권세를 가진 하나님의 아들임을 분명히 밝히십니다.\n\n예수님은 당시 종교 지도자들의 근본적인 문제를 지적하십니다. "너희가 성경에서 영생을 얻는 줄 생각하고 성경을 연구하거니와 이 성경이 곧 내게 대하여 증언하는 것이니라. 그러나 너희가 영생을 얻기 위하여 내게 오기를 원하지 아니하는도다"(요 5:39-40). 성경을 연구하면서도 성경이 가리키는 예수님께로는 나아오지 않는 모순, 이것이 바로 생명 없는 종교의 비극입니다. 참된 생명은 율법의 조문을 지키는 데서 오는 것이 아니라, 생명의 주인이신 예수님께 나아갈 때 주어집니다. 38년 된 병자처럼 우리도 자신의 무력함을 인정하고 예수님의 음성에 순종할 때, 죽음에서 생명으로 옮겨지는 부활의 능력을 경험하게 될 것입니다.', E'오늘의 핵심\n38년 된 병자를 고치신 예수님은 안식일에도 생명을 살리시는 하나님의 아들이시며, 종교의 형식이 아닌 생명 그 자체이십니다.\n\n묵상 질문\n1. 38년 동안 누워있던 병자처럼, 나에게도 오랜 세월 포기하고 있던 영역이 있나요?\n2. 종교적 형식과 규정에 갇혀 정작 생명이신 예수님을 놓치고 있지는 않나요?\n3. "내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었다"는 예수님의 약속이 내 삶에서 실제가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-21', E'영원한 생명수이신 예수 (요한복음 6장)', E'요한복음 6장', E'유월절이 가까워진 때, 예수님께서는 갈릴리 바다 건너편으로 가셨습니다. 병자들을 고치시는 표적을 본 큰 무리가 따라왔고, 예수님은 그들의 육신의 필요를 아셨습니다. 빌립에게 "우리가 어디서 떡을 사서 이 사람들을 먹이겠느냐"고 물으신 것은 단순한 질문이 아니었습니다. 제자들의 믿음을 시험하시면서 동시에 더 큰 진리를 가르치려 하신 것입니다.\n\n한 아이가 가진 보리떡 다섯 개와 물고기 두 마리는 오천 명 앞에서 터무니없이 부족해 보였습니다. 그러나 예수님의 손에서 그것은 모든 사람을 배부르게 하고도 열두 바구니가 남는 풍성함이 되었습니다. 이 기적은 단순한 양식의 공급이 아니라, 예수님이 누구신지를 보여주는 표적이었습니다.\n\n그런데 무리는 표적의 의미를 놓쳤습니다. 그들은 예수님을 억지로 왕 삼으려 했고, 이튿날에는 또 떡을 얻으려 찾아왔습니다. 예수님은 그들의 마음을 꿰뚫어 보시며 말씀하셨습니다. "썩을 양식을 위하여 일하지 말고 영생하도록 있는 양식을 위하여 하라." 그리고 놀라운 선언을 하십니다. "내가 곧 생명의 떡이니라."\n\n광야에서 만나를 먹었던 조상들도 결국 죽었지만, 예수님이 주시는 떡을 먹는 자는 영원히 살 것이라는 말씀은 유대인들에게 충격이었습니다. 더욱이 "내 살을 먹고 내 피를 마시는 자는 영생을 가졌고"라는 말씀은 그들이 도저히 받아들일 수 없는 것이었습니다. 그들은 육신의 눈으로만 보았기에 영적 진리를 깨닫지 못했습니다.\n\n예수님은 우리의 일용할 양식도 공급하시지만, 더 중요한 것은 영원한 생명의 양식이 되어주신다는 사실입니다. 하늘에서 내려온 참된 떡이신 예수님을 믿고 받아들이는 것, 그것이 하나님께서 원하시는 일입니다. 오늘도 우리는 썩어질 것들을 추구하며 분주히 살아갑니다. 그러나 예수님은 우리에게 묻고 계십니다. 무엇이 당신을 진정으로 살게 하는가?', E'오늘의 핵심\n예수님은 오병이어의 기적을 통해 육신의 양식을 공급하셨지만, 궁극적으로는 자신이 하늘에서 내려온 생명의 떡임을 선포하시며 영원한 생명을 주시는 구주이심을 계시하셨습니다.\n\n묵상 질문\n1. 나는 예수님께 무엇을 구하고 있나요? 썩을 양식입니까, 영생하는 양식입니까?\n2. 내가 가진 작은 것(오병이어)을 예수님께 드릴 때 어떤 일이 일어날 수 있을까요?\n3. "내가 곧 생명의 떡이니라"는 예수님의 선언이 오늘 내 삶에 어떤 의미가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-22', E'죄인을 감싸주시는 예수', E'요한복음 8장', E'어느 날 서기관들과 바리새인들이 음행 중에 잡힌 여인을 예수님 앞으로 끌고 와서 어떻게 할 것인지 물으며 예수님을 궁경에 빠뜨립니다. 그때 예수님께서는 "너희 중에 죄 없는 자가 먼저 돌로 치라"(요 8:7)라고 말씀하셨습니다. 잠깐의 정적이 흐른 후, 돌을 들었던 자들이 모두 흩어지고 그 여인과 예수님 둘만 남았습니다. 그때 예수님께서 그 여인에게 "나도 너를 정죄하지 아니하노니 가서 다시는 죄를 범하지 말라"(요 8:11)라고 말씀하십니다. 이처럼 예수님께서는 죄인들의 부끄러움을 덮고 용서해주시며 새로운 길을 열어주셨습니다.\n말씀 후에 예수님께서는 "나는 세상의 빛이니 나를 따르는 자는 어둠에 다니지 아니하고 생명의 빛을 얻으리라"(요 8:12)라고 말씀하십니다. 이 말씀을 들은 바리새인들이 예수님께 대적하자 예수님께서는 "내 증언이 참되니 나는 내가 어디서 오며 어디로 가는 것을 알거니와 너희는 내가 어디서 오며 어디로 가는 것을 알지 못하느니라"(요 8:14)라고 말씀하십니다. 그러나 진리의 말씀을 가르치면 가르칠수록 그들은 더욱 예수님을 의심합니다. 예수님께서는 그들을 책망하시며 "사람이 내 말을 지키면 영원히 죽음을 보지 아니하리라"(요 8:51)라고 말씀하십니다.', E'오늘의 핵심\n죄인을 감싸시는 예수님의 지혜로운 대답은 불의한 자들의 계략을 뛰어넘어 오히려 시험하는 자들을 부끄럽게 합니다.\n\n묵상 질문\n1. 예수님은 죄인을 심판하지 않고 왜 용서와 회복을 주셨을까요?\n2. 내가 다른 사람의 잘못을 볼 때, 예수님처럼 감싸고 용서할 수 있을까요?\n3. 예수님의 용서 앞에서 나는 어떻게 변화되고 싶은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-23', E'선한 목자이신 예수 (요한복음 9장)', E'요한복음 9장', E'날 때부터 맹인이었던 한 사람의 인생이 예수님을 만나 완전히 바뀌는 놀라운 이야기가 요한복음 9장에 펼쳐집니다. 제자들은 이 사람의 불행을 보며 누구의 죄 때문인지 묻지만, 예수님은 전혀 다른 관점을 제시하십니다. "이 사람이나 그 부모의 죄로 인한 것이 아니라 그에게서 하나님이 하시는 일을 나타내고자 하심이라"(요 9:3). 고통의 원인을 따지기보다 하나님께서 그 고통을 통해 무엇을 이루실지에 주목하라는 가르침입니다.\n\n예수님은 침과 흙을 이겨 그의 눈에 바르시고 실로암 못에 가서 씻으라고 하십니다. 실로암은 ''보냄을 받았다''는 뜻인데, 이는 단순한 치유 이상의 의미를 담고 있습니다. 그가 순종하여 씻고 돌아왔을 때, 평생 닫혀있던 눈이 열렸습니다. 그런데 이 놀라운 기적이 안식일에 일어났다는 이유로 바리새인들은 예수님을 정죄하려 합니다. 그들은 표적의 의미보다 율법 조문에만 매달렸던 것입니다.\n\n치유받은 사람은 반복되는 심문 속에서도 흔들리지 않습니다. 처음에는 "예수라 하는 그 사람"이라고 했다가, "선지자"라고 고백하고, 마침내 예수님 앞에서 "주여 내가 믿나이다"라며 경배합니다. 반면 바리새인들은 점점 더 완고해져 갑니다. 예수님은 이들에게 "너희가 맹인이 되었더라면 죄가 없으려니와 본다고 하니 너희 죄가 그대로 있느니라"고 말씀하십니다. 육신의 눈은 뜨였지만 영적으로는 맹인인 그들의 모습을 지적하신 것입니다.\n\n이 사건은 단순한 치유 기적을 넘어 영적 각성에 관한 깊은 가르침을 담고 있습니다. 참된 시각은 육신의 눈이 아닌 믿음의 눈으로 보는 것임을, 그리고 하나님의 영광은 우리의 연약함을 통해서도 나타날 수 있음을 보여줍니다.', E'오늘의 핵심\n예수님은 날 때부터 맹인된 사람을 고치시면서 육신의 치유와 함께 영적인 눈을 열어주셨고, 오히려 본다고 자부하는 종교지도자들의 영적 맹목을 드러내셨습니다.\n\n묵상 질문\n1. 내 삶의 고통과 연약함을 통해 하나님께서 나타내시려는 영광은 무엇일까요?\n2. 종교적 지식과 관습에 갇혀 예수님의 참된 모습을 보지 못하고 있는 부분은 없나요?\n3. 치유받은 맹인처럼 점진적으로 깊어지는 신앙고백을 나도 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-24', E'선한 목자이신 예수 (요한복음 10장)', E'요한복음 10장', E'예수님께서는 9장에서 날 때부터 맹인 된 사람을 고치신 후, 바리새인들과의 대립이 심화되는 상황에서 자신의 정체성을 더욱 분명하게 드러내십니다. 목자와 양의 비유를 통해 참된 지도자의 모습이 무엇인지 가르쳐 주십니다. 양의 우리에 문으로 들어가지 않고 다른 곳으로 넘어가는 자는 절도요 강도라고 하시면서, 참된 목자는 문을 통해 들어가며 양들이 그의 음성을 알아듣는다고 말씀하십니다. \n\n예수님은 자신을 "양의 문"이자 "선한 목자"라고 선언하십니다. 문이 되신다는 것은 구원의 유일한 통로가 되심을 의미합니다. 선한 목자가 되신다는 것은 양들을 위해 목숨까지 버리는 희생적 사랑을 실천하심을 뜻합니다. 삯꾼은 위기가 닥치면 도망가지만, 선한 목자는 양을 위해 자기 생명을 내어놓습니다. 이것이 바로 십자가를 향해 가시는 예수님의 결단이었습니다.\n\n수전절 때 성전에서 유대인들이 예수님께 그리스도인지 밝히 말하라고 다그칩니다. 예수님은 이미 말했으나 그들이 믿지 않는 것은 그들이 예수님의 양이 아니기 때문이라고 하십니다. "내 양은 내 음성을 들으며 나는 그들을 알며 그들은 나를 따르느니라"(요 10:27). 참된 양은 목자의 음성을 알아듣고 따릅니다. 그리고 선한 목자이신 예수님은 자기 양들에게 영생을 주시며, 그 누구도 그들을 빼앗을 수 없다고 약속하십니다.\n\n예수님과 아버지가 하나라는 선언은 유대인들을 격분시켜 돌로 치려 했습니다. 그들에게는 신성모독으로 들렸기 때문입니다. 하지만 예수님은 자신이 행하는 일들이 곧 아버지의 일이며, 이를 통해 아버지와 자신의 하나 됨을 알 수 있다고 말씀하십니다. 요단 강 건너편으로 가신 예수님을 많은 사람들이 찾아왔고, 그곳에서 많은 이들이 예수님을 믿게 됩니다. 세례 요한의 증언이 모두 참되었음을 깨달은 것입니다.', E'오늘의 핵심\n예수님은 양들을 위해 목숨을 버리는 선한 목자이시며, 구원의 유일한 문이 되십니다. 그분의 양들은 목자의 음성을 알아듣고 따르며 영생의 약속을 받습니다.\n\n묵상 질문\n1. 내가 따르고 있는 목소리는 정말 선한 목자이신 예수님의 음성인가요?\n2. 위기의 때에도 나를 버리지 않으시는 주님의 신실하심을 어떻게 경험했나요?\n3. 영생의 확신 가운데 살아가기 위해 오늘 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-25', E'선한 목자이신 예수 (요한복음 11장)', E'요한복음 11장', E'베다니에 사는 나사로가 병들었다는 소식이 예수님께 전해집니다. 마리아와 마르다는 오라비의 위급함을 알리며 주님의 도움을 구했지만, 예수님께서는 "이 병은 죽을 병이 아니라 하나님의 영광을 위함이요 하나님의 아들이 이로 말미암아 영광을 받게 하려 함이라"(요 11:4)고 말씀하시며 이틀을 더 머무르십니다. 제자들은 유대인들의 돌로 치려던 위협을 기억하며 두려워했지만, 예수님께서는 죽은 나사로를 살리시기 위해 베다니로 향하십니다.\n\n나사로가 무덤에 있은 지 나흘째 되던 날, 마르다는 예수님을 맞으며 "주께서 여기 계셨더라면"이라는 아쉬움을 표현합니다. 그러나 동시에 지금이라도 주님께서 구하시면 하나님께서 응답하실 것이라는 믿음을 고백합니다. 이어 마리아도 같은 말로 슬픔을 토로하자, 예수님께서는 그들과 함께 우시며 인간의 슬픔에 깊이 공감하시는 모습을 보여주십니다. \n\n무덤 앞에서 예수님께서는 하나님께 감사 기도를 드리신 후 "나사로야 나오라"고 부르십니다. 죽은 지 나흘이나 된 나사로가 살아나는 놀라운 표적이 일어납니다. 이 일을 목격한 많은 유대인들이 예수님을 믿게 되었지만, 종교 지도자들은 오히려 더욱 격렬하게 예수님을 죽이려는 계획을 세웁니다. 대제사장 가야바는 한 사람이 백성을 위해 죽는 것이 유익하다고 말하는데, 이는 자신도 모르게 예수님의 대속적 죽음을 예언한 것이었습니다.\n\n나사로의 부활 사건은 예수님께서 "나는 부활이요 생명이니"라고 선포하신 말씀이 현실이 되는 순간이었습니다. 죽음의 권세를 이기시고 생명을 주시는 분이 바로 우리 앞에 계신다는 것을 보여주신 것입니다.', E'오늘의 핵심\n예수님께서는 나사로를 살리심으로써 자신이 부활이요 생명이심을 증명하셨고, 인간의 슬픔에 함께 우시며 공감하시는 참된 구원자이심을 보여주셨습니다.\n\n묵상 질문\n1. 주님께서 나사로의 죽음을 미리 아시면서도 이틀을 더 머무르신 이유는 무엇일까요?\n2. 예수님께서 눈물을 흘리신 모습에서 우리는 어떤 위로를 받을 수 있을까요?\n3. 나에게도 "주께서 여기 계셨더라면"이라고 아쉬워하는 상황이 있나요? 그럼에도 주님을 신뢰할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-26', E'새 계명을 주심', E'요한복음 13장', E'유월절 엿새 전에 예수님께서는 나사로의 집으로 가셔서 거기서 유하십니다. 예수님을 위해 잔치할 때, 마리아가 비싼 향유를 예수님의 발에 부습니다. 가롯 유다가 그 여인의 행동을 책망하자 예수님께서는 "나의 장례할 날을 위하여 그것을 간직하게 하라"(요 12:7)라고 하시며 죽으심을 예고하십니다. 유대인의 큰 무리가 예수님께서 나사로의 집에 계시다는 소식을 듣고 그곳으로 옵니다. 나사로를 살리신 예수님과 정말로 나사로가 살아나는지를 보고 싶어 한 것입니다. 나사로에게 사람들이 많은 관심을 보이자 대제사장들은 나사로까지 죽이려고 모의합니다.\n이튿날, 예수님께서 예루살렘으로 오신다는 소식을 들은 큰 무리가 종려나무 가지를 가지고 "호산나 찬송하리로다 주의 이름으로 오시는 이 곧 이스라엘의 왕이시여"(요 12:13)라고 소리 높이며 예수님을 맞이합니다. 예수님께서는 마지막 만찬을 나누신 후 제자들의 발을 씻기시며 섬김의 본을 보여주십니다. 그리고 예수님께서는 제자들에게 "새 계명을 너희에게 주노니 서로 사랑하라 내가 너희를 사랑한 것 같이 너희도 서로 사랑하라 너희가 서로 사랑하면 이로써 모든 사람이 너희가 내 제자인 줄 알리라"(요 13:34-35)라고 말씀하십니다.', E'오늘의 핵심\n제자들 그리고 이 땅에 있는 자신의 사람들을 사랑하시되 끝까지 사랑하신 예수님께서 "너희도 서로 사랑하라"라는 새 계명을 주십니다.\n\n묵상 질문\n1. 예수님의 죽음을 앞두고도 사랑으로 베푸신 그 마음은 무엇일까요?\n2. 자기 것을 아낌없이 드리는 마리아처럼 나는 무엇을 드릴 수 있을까요?\n3. 예수님의 죽음과 부활을 믿고 따르겠다고 기도할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-28', E'예수의 고별 설교 (요한복음 14장)', E'요한복음 14장', E'예수님께서 십자가를 앞두고 제자들과 함께하시는 마지막 밤입니다. 곧 떠나야 하는 상황에서 제자들의 마음은 근심으로 가득했을 것입니다. 그런 제자들에게 예수님은 "너희는 마음에 근심하지 말라"(요 14:1)고 말씀하십니다. 이것은 단순한 위로가 아니라 확실한 약속에 근거한 선언이었습니다. 아버지의 집에 거할 곳을 예비하러 가시며, 다시 오셔서 제자들을 영접하시겠다는 약속입니다.\n\n도마가 길을 모르겠다고 고백했을 때, 예수님은 놀라운 선언을 하십니다. 길을 가르쳐 주신 것이 아니라 "내가 곧 길이요 진리요 생명"이라고 자기 자신을 제시하신 것입니다. 우리가 찾는 것이 방법이나 지식이라면, 예수님은 그 모든 것을 넘어서는 존재 자체로 우리에게 다가오십니다. 아버지께로 가는 유일한 길은 예수님 자신이며, 예수님을 통해서만 우리는 아버지를 알고 만날 수 있습니다.\n\n빌립이 아버지를 보여달라고 요청했을 때도 마찬가지입니다. 예수님은 자신을 본 자는 이미 아버지를 보았다고 말씀하십니다. 예수님과 아버지의 완전한 하나 됨이 여기서 드러납니다. 아버지가 예수님 안에, 예수님이 아버지 안에 계시는 이 신비로운 연합은 우리의 이해를 넘어서지만, 예수님의 말씀과 행하심을 통해 분명히 계시됩니다.\n\n이어서 예수님은 또 다른 놀라운 약속을 주십니다. 보혜사 성령을 보내주시겠다는 것입니다. 예수님이 떠나시지만 제자들을 고아처럼 버려두지 않으시고, 성령을 통해 영원히 함께하시겠다는 약속입니다. 성령은 진리의 영으로서 제자들에게 모든 것을 가르치시고, 예수님이 하신 말씀을 생각나게 하실 것입니다. 이는 단순한 위로를 넘어서는 능력의 약속입니다.\n\n마지막으로 예수님은 평안을 약속하십니다. 세상이 주는 평안과는 다른, 예수님만이 주실 수 있는 참된 평안입니다. 이 평안은 환경에 좌우되지 않는 평안이며, 예수님과의 관계에서 나오는 평안입니다. 예수님을 사랑하고 그의 계명을 지키는 자에게 아버지와 아들이 함께 거하시겠다는 약속은 우리가 누릴 수 있는 가장 큰 복입니다.', E'오늘의 핵심\n예수님은 떠나시지만 제자들을 고아처럼 버려두지 않으시고, 성령을 보내주시며 영원한 거처를 예비하시겠다고 약속하십니다.\n\n묵상 질문\n1. 예수님이 "길이요 진리요 생명"이라는 말씀이 오늘 나의 삶에 어떤 의미가 있나요?\n2. 내가 근심하고 두려워하는 것들을 예수님께 맡기고 그분의 평안을 받고 있나요?\n3. 성령님이 나와 함께하신다는 약속을 일상에서 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-29', E'예수의 고별 설교 (요한복음 15장)', E'요한복음 15장', E'예수님께서는 제자들과의 마지막 시간에 포도나무 비유를 통해 가장 중요한 영적 원리를 가르쳐 주십니다. "나는 참포도나무요 내 아버지는 농부라"(15:1)는 선언으로 시작되는 이 비유는 우리가 그리스도 안에서 어떻게 살아가야 하는지를 보여줍니다. 가지가 나무에 붙어 있어야만 생명을 유지하고 열매를 맺듯이, 우리도 예수님 안에 거해야만 참된 열매를 맺을 수 있습니다.\n\n이 비유에서 주목할 것은 ''거한다''는 표현이 반복적으로 나타난다는 점입니다. 예수님은 단순히 믿음을 갖는 것을 넘어, 지속적으로 그분 안에 머무는 삶을 요구하십니다. 그리고 그 거함의 구체적인 모습은 사랑으로 나타납니다. 아버지께서 아들을 사랑하신 것같이 예수님이 우리를 사랑하셨고, 이제 우리도 그 사랑 안에 거하며 서로 사랑해야 한다는 것입니다. 놀랍게도 예수님은 이렇게 사랑 안에 거하는 제자들을 더 이상 종이 아닌 ''친구''라고 부르십니다. 주인과 종의 관계가 아닌, 모든 것을 나누는 친밀한 관계로 초청하신 것입니다.\n\n그러나 이 사랑의 관계는 세상과의 갈등을 동반합니다. 예수님은 제자들이 세상의 미움을 받게 될 것을 분명히 말씀하십니다. 세상이 먼저 예수님을 미워했듯이, 그분께 속한 제자들도 미움을 받게 됩니다. 하지만 이 어려움 가운데서도 소망이 있습니다. 바로 아버지께로부터 오시는 진리의 성령, 보혜사께서 예수님을 증언하실 것이며, 제자들도 그 증언에 동참하게 될 것입니다.\n\n포도나무에 붙어 있는 가지처럼, 우리의 생명과 열매는 전적으로 그리스도께 의존합니다. 내 힘과 노력으로 무언가를 이루려 하기보다, 먼저 그분 안에 거하는 것, 그분의 사랑 안에 머무는 것이 우선입니다. 오늘도 참포도나무이신 예수님께 깊이 연결되어, 그분의 생명으로 살아가는 하루가 되기를 소망합니다.', E'오늘의 핵심\n예수님은 참포도나무로서 우리가 그분 안에 거할 때만 열매를 맺을 수 있음을 가르치시며, 그 거함의 핵심은 서로 사랑하는 것임을 말씀하십니다.\n\n묵상 질문\n1. 나는 지금 포도나무이신 예수님께 얼마나 깊이 연결되어 있나요?\n2. 예수님이 나를 ''친구''라 부르신다는 사실이 내 삶에 어떤 변화를 가져다주나요?\n3. 세상의 미움을 받을 때도 사랑 안에 거할 수 있는 힘은 어디서 오나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-30', E'제자들을 위한 예수의 기도 (요한복음 16장)', E'요한복음 16장', E'예루살렘의 다락방에서 예수님께서는 제자들에게 마지막 말씀을 전하고 계셨습니다. 십자가의 죽음을 눈앞에 둔 시점에서, 예수님께서는 곧 닥칠 환난과 박해에 대해 미리 알려주십니다. 제자들이 회당에서 쫓겨날 뿐 아니라 그들을 죽이는 자들이 오히려 하나님을 섬긴다고 착각할 것이라는 충격적인 예언이었습니다. 이러한 일들이 일어나는 근본 이유는 박해자들이 아버지 하나님과 예수님을 알지 못하기 때문입니다.\n\n예수님의 떠나심에 대한 말씀은 제자들의 마음을 근심으로 가득 채웠습니다. 그러나 예수님께서는 놀라운 역설을 제시하십니다. 당신이 떠나가는 것이 오히려 제자들에게 유익이 된다는 것입니다. 왜냐하면 예수님께서 떠나가셔야만 보혜사 성령께서 오실 수 있기 때문입니다. 성령께서는 죄와 의와 심판에 대하여 세상을 책망하시고, 제자들을 모든 진리 가운데로 인도하실 것입니다.\n\n예수님께서는 제자들이 이해하지 못하는 수수께끼 같은 말씀을 하십니다. "조금 있으면 너희가 나를 보지 못하겠고 또 조금 있으면 나를 보리라"(요 16:16). 이는 곧 있을 십자가의 죽음과 부활을 암시하는 말씀이었습니다. 제자들의 슬픔은 해산의 고통처럼 잠시뿐이며, 곧 기쁨으로 변할 것입니다. 부활하신 주님을 만날 때 그들의 기쁨은 그 누구도 빼앗을 수 없는 영원한 기쁨이 될 것입니다.\n\n예수님께서는 제자들에게 새로운 기도의 길을 열어주십니다. 이제 그들은 예수님의 이름으로 아버지께 직접 구할 수 있게 됩니다. 이것은 예수님을 통해 하나님과의 새로운 관계가 시작됨을 의미합니다. 마지막으로 예수님께서는 "담대하라 내가 세상을 이기었노라"는 승리의 선언으로 제자들을 격려하십니다. 세상의 환난 가운데서도 예수님 안에서 참된 평안을 누릴 수 있다는 약속이었습니다.', E'오늘의 핵심\n예수님께서는 십자가를 앞두고 제자들에게 성령의 오심과 그분을 통한 위로, 그리고 세상을 이기신 승리를 약속하십니다.\n\n묵상 질문\n1. 내가 경험하는 고난과 어려움 속에서도 성령님의 위로하심을 느끼고 있나요?\n2. 예수님의 이름으로 기도할 수 있는 특권을 얼마나 감사하며 누리고 있나요?\n3. "내가 세상을 이기었노라"는 예수님의 선언이 오늘 나의 삶에 어떤 담대함을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-08-31', E'제자들을 위한 예수의 기도 (요한복음 17장)', E'요한복음 17장', E'십자가를 눈앞에 둔 예수님께서 눈을 들어 하늘을 우러러 기도하십니다. 이 기도는 대제사장이신 예수님께서 드리는 중보기도로, 제자들과 모든 믿는 자들을 위한 간절한 호소입니다. 예수님께서는 먼저 아버지 하나님께 자신을 영화롭게 해 달라고 구하시는데, 이것은 개인적 영광을 위함이 아니라 아버지를 영화롭게 하기 위함입니다. "영생은 곧 유일하신 참 하나님과 그가 보내신 자 예수 그리스도를 아는 것이니이다"(요 17:3)라는 예수님의 선언은 영생의 본질이 하나님과의 친밀한 관계에 있음을 보여줍니다.\n\n예수님의 기도는 제자들을 향한 깊은 사랑으로 이어집니다. 예수님께서는 제자들이 세상에 남아 있을 동안 아버지의 이름으로 그들을 보전해 주시기를 간구하십니다. 세상이 그들을 미워할 것이지만, 그들을 세상에서 데려가시기를 구하지 않고 오히려 악에 빠지지 않도록 보호해 주시기를 청하십니다. 이는 그리스도인들이 세상 속에서 살아가되 세상에 속하지 않는 거룩한 삶을 살아야 함을 가르쳐 줍니다.\n\n특별히 예수님께서는 당시 제자들만이 아니라 그들의 말을 통해 믿게 될 미래의 모든 신자들을 위해서도 기도하십니다. 그 기도의 핵심은 ''하나 됨''입니다. 아버지와 아들이 하나이신 것처럼, 모든 믿는 자들도 그 사랑 안에서 하나가 되기를 간구하십니다. 이 하나 됨은 단순한 조직적 통합이 아니라 삼위일체 하나님의 사랑 안에서 이루어지는 영적 연합입니다. 예수님의 이 마지막 기도는 십자가의 고난을 앞두고도 자신보다 제자들과 교회를 먼저 생각하시는 그분의 희생적 사랑을 보여주며, 오늘날 우리에게도 여전히 유효한 중보의 기도가 되고 있습니다.', E'오늘의 핵심\n예수님께서는 십자가를 앞두고 제자들과 모든 믿는 자들의 보호와 하나 됨을 위해 간절히 기도하시며, 하나님의 사랑이 그들 안에 거하기를 구하십니다.\n\n묵상 질문\n1. 예수님께서 영생을 ''하나님과 그리스도를 아는 것''이라고 정의하신 의미는 무엇일까요?\n2. 세상 속에 살면서도 세상에 속하지 않는다는 것은 어떤 삶을 의미할까요?\n3. 교회의 하나 됨을 위해 내가 실천할 수 있는 구체적인 사랑의 행동은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-01', E'예수의 십자가 사역 (요한복음 18장)', E'요한복음 18장', E'예수님은 모든 것을 아셨습니다. 유다가 군대를 이끌고 올 것도, 자신이 십자가에서 죽게 될 것도 알고 계셨습니다. 그런데 놀라운 것은 예수님이 숨거나 피하지 않으셨다는 사실입니다. 오히려 먼저 나아가셔서 "너희가 누구를 찾느냐"고 물으셨습니다. "내가 그니라"라고 말씀하시자 무리가 땅에 엎드러졌습니다. 이 장면은 잡히러 온 자들 앞에서도 예수님이 여전히 주권자이셨음을 보여줍니다. 예수님의 체포는 당하신 것이 아니라, 스스로 내어주신 것이었습니다.\n\n그 순간에도 예수님은 제자들을 지키셨습니다. "나를 찾거든 이 사람들이 가는 것은 용납하라." 아버지께서 맡기신 자를 하나도 잃지 않겠다는 그 약속을 끝까지 지키신 것입니다. 반면 베드로는 목숨을 걸고 따르겠다던 고백과 달리 세 번이나 예수님을 부인합니다. 추운 밤, 불 앞에 서서 몸을 녹이던 그 모습은 두려움 앞에서 무너지는 우리의 솔직한 자화상이기도 합니다.\n\n빌라도 앞에서 예수님은 "내 나라는 이 세상에 속한 것이 아니니라"고 선언하셨습니다. 세상의 권력과 군대로 세우는 나라가 아니라 진리로 세우시는 나라입니다. 빌라도는 "진리가 무엇이냐"고 물었지만 답을 기다리지 않았습니다. 진리이신 분이 바로 눈앞에 서 계셨는데도 알아보지 못한 것입니다. 결국 빌라도는 죄 없음을 알면서도 군중의 외침에 예수님을 넘기고, 무리는 예수님 대신 강도 바라바를 택합니다.\n\n직장에서, 학교에서, 관계 속에서 우리도 ''내가 그리스도인이냐''는 질문 앞에 서게 됩니다. 베드로처럼 두려워 부인할 때도 있을 것입니다. 그러나 우리를 끝까지 지키시는 예수님의 사랑을 기억한다면, 우리도 그분의 진리 앞에 담대히 설 수 있을 것입니다.', E'오늘의 핵심\n예수님은 자신의 고난을 미리 아시면서도 스스로 십자가의 길로 나아가셨고, 그 과정에서도 제자들을 끝까지 보호하시며 하나님의 뜻을 이루셨습니다.\n\n묵상 질문\n1. 예수님이 스스로 체포당하러 나가신 이유는 무엇일까요?\n2. 베드로의 부인을 통해 나의 연약함을 어떻게 돌아볼 수 있을까요?\n3. 빌라도처럼 진리를 외면하고 있는 나의 모습은 없나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-02', E'예수의 십자가 사역 (요한복음 19장)', E'요한복음 19장', E'빌라도의 법정에서 예수님은 채찍에 맞으시고 가시관을 쓰셨습니다. 자색 옷을 입히고 조롱하는 군인들 앞에서도 예수님은 침묵하셨습니다. 빌라도는 예수님께서 죄가 없음을 알았지만, 유대인들의 압력에 굴복하고 말았습니다. "이 사람을 놓으면 가이사의 충신이 아니니이다"라는 그들의 협박은 빌라도의 정치적 생명을 위협하는 것이었습니다. 결국 빌라도는 진리보다 권력을, 정의보다 안위를 택했습니다.\n\n예수님은 빌라도에게 말씀하셨습니다. "위에서 주지 아니하셨더라면 나를 해할 권한이 없었으리니." 이 말씀은 십자가 사건조차도 하나님의 주권 아래 있음을 보여줍니다. 세상의 권세자들이 예수님을 심판하는 것처럼 보였지만, 실상은 하나님께서 인류 구원의 계획을 이루어 가시는 과정이었습니다. 대제사장들이 "가이사 외에는 우리에게 왕이 없나이다"라고 외친 것은 하나님의 백성이 얼마나 타락했는지를 보여주는 비극적인 고백이었습니다.\n\n골고다 언덕에서 예수님은 두 강도와 함께 십자가에 못 박히셨습니다. 빌라도가 쓴 ''나사렛 예수 유대인의 왕''이라는 패는 히브리어, 로마어, 헬라어로 기록되었습니다. 이는 예수님의 왕 되심이 온 세상에 선포되는 순간이었습니다. 십자가 아래에서 군인들은 예수님의 옷을 나누며 제비를 뽑았고, 이는 시편의 예언을 성취하는 것이었습니다.\n\n십자가 위에서도 예수님은 어머니를 돌보셨습니다. 사랑하는 제자에게 어머니를 부탁하시는 모습은 끝까지 사랑을 실천하시는 주님의 성품을 보여줍니다. 그리고 "다 이루었다"는 마지막 선언과 함께 숨을 거두셨습니다. 이는 패배의 탄식이 아니라 승리의 선언이었습니다. 인류 구원을 위한 하나님의 계획이 완성되는 순간이었습니다.\n\n예수님이 돌아가신 후, 숨어있던 두 제자가 나타났습니다. 아리마대 요셉과 니고데모는 용기를 내어 예수님의 시신을 거두었습니다. 백 리트라나 되는 향품을 가져온 니고데모의 행동은 왕의 장례에 합당한 예우였습니다. 새 무덤에 장사되신 예수님의 모습은 죄 없으신 분이 우리의 죄를 대신 지셨음을 보여줍니다. 어둠이 가장 짙을 때, 하나님은 이미 부활의 새벽을 준비하고 계셨습니다.', E'오늘의 핵심\n십자가는 세상의 눈에는 실패와 죽음의 자리였지만, 하나님의 계획 안에서는 인류 구원이 완성되는 영광의 자리였습니다.\n\n묵상 질문\n1. 빌라도처럼 진리를 알면서도 세상의 압력에 굴복한 경험이 있나요?\n2. 예수님께서 십자가에서 "다 이루었다"고 하신 말씀이 내 삶에 어떤 의미가 있나요?\n3. 아리마대 요셉과 니고데모처럼 두려움을 극복하고 신앙을 고백해야 할 때는 언제인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-04', E'예수의 십자가 사역 (요한복음 20장)', E'요한복음 20장', E'안식 후 첫날 이른 새벽, 막달라 마리아가 무덤을 찾았을 때 돌이 옮겨진 빈 무덤을 발견합니다. 그녀는 즉시 베드로와 요한에게 달려가 이 소식을 전했고, 두 제자는 서둘러 무덤으로 향합니다. 무덤 안에는 예수님의 시신은 없고 세마포와 머리 수건만 가지런히 놓여 있었습니다. 특별히 머리 수건이 따로 개어져 있었다는 세밀한 묘사는 이것이 도둑질이 아닌 질서정연한 부활의 현장임을 보여줍니다. 요한은 이 광경을 보고 비로소 믿게 되었다고 고백합니다.\n\n홀로 무덤가에 남아 울고 있던 마리아에게 부활하신 주님이 먼저 나타나십니다. 처음엔 동산지기로 착각했지만, 예수님께서 그녀의 이름을 부르시자 마리아는 "랍오니"라고 응답합니다. 이 친밀한 만남은 부활이 단순한 역사적 사건이 아니라 개인적이고 인격적인 만남임을 보여줍니다. 예수님은 마리아에게 제자들에게 가서 부활의 소식을 전하라고 명하십니다. "내가 내 아버지 곧 너희 아버지께로 올라간다"는 이 메시지는 예수님의 부활로 인해 우리도 하나님을 아버지로 부를 수 있게 되었음을 선포합니다.\n\n저녁이 되자 유대인들을 두려워하며 문을 걸어 잠근 채 숨어있던 제자들에게 부활하신 예수님이 나타나셨습니다. "너희에게 평강이 있을지어다"라는 인사와 함께 손과 옆구리의 상처를 보여주시며 제자들의 두려움을 평강으로 바꾸어 주십니다. 그리고 숨을 내쉬시며 "성령을 받으라"고 말씀하시는데, 이는 창조 때 생기를 불어넣으신 것처럼 새로운 창조의 시작을 알리는 것입니다. 아버지께서 예수님을 보내신 것같이 이제 예수님께서 제자들을 세상으로 파송하십니다.\n\n그 자리에 없었던 도마는 다른 제자들의 증언을 믿지 못하고 직접 못 자국을 만져보겠다고 고집합니다. 여드레 후 예수님은 도마의 요구대로 손과 옆구리를 보이시며 "믿음 없는 자가 되지 말고 믿는 자가 되라"고 권면하십니다. 이에 도마는 "나의 주님이시요 나의 하나님이시니이다"라는 가장 분명한 신앙고백으로 응답합니다. 예수님은 보지 못하고 믿는 자들이 복되다고 선언하시는데, 이는 오늘날 우리를 향한 축복의 말씀이기도 합니다.', E'오늘의 핵심\n부활하신 예수님은 두려움에 갇힌 제자들을 찾아오셔서 평강을 주시고, 성령으로 새롭게 하시며, 세상을 향한 사명자로 파송하십니다.\n\n묵상 질문\n1. 빈 무덤 앞에서 울고 있던 마리아처럼, 나도 주님의 부재를 경험하며 슬퍼한 적이 있나요?\n2. 두려움에 문을 걸어 잠근 제자들에게 찾아오신 주님이 내게도 어떤 평강을 주실까요?\n3. "보지 못하고 믿는 자가 복되다"는 말씀이 오늘 나의 신앙에 어떤 도전과 위로를 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-05', E'예수의 십자가 사역 (요한복음 21장)', E'요한복음 21장', E'부활하신 예수님이 디베랴 호숫가에 다시 나타나셨습니다. 베드로와 제자들은 밤새 그물을 던졌지만 아무것도 잡지 못한 채 새벽을 맞이했습니다. 바로 그때 낯선 사람이 "그물을 배 오른편에 던지라"고 말씀하셨고, 순종했을 때 놀라운 일이 일어났습니다. 153마리의 큰 물고기로 그물이 가득 찼지만 찢어지지 않았습니다. 이 기적을 통해 제자들은 그분이 주님이심을 알아보았습니다.\n\n갈릴리 호수는 제자들에게 특별한 곳이었습니다. 처음 부르심을 받았던 곳이자, 이제는 좌절과 실패 후에 돌아온 일상의 자리였습니다. 그런데 부활하신 주님은 바로 그 일상의 자리에서 제자들을 다시 만나주셨습니다. 숯불 위에는 이미 생선이 놓여 있었고 떡도 준비되어 있었습니다. 제자들을 위해 아침을 준비하신 주님의 섬세한 사랑이 드러나는 순간입니다.\n\n조반을 나눈 후, 예수님은 베드로에게 세 번 물으셨습니다. "네가 나를 사랑하느냐?" 베드로가 세 번 부인했던 그 아픔의 자리에서, 주님은 세 번의 사랑 고백을 통해 그를 회복시키셨습니다. 그리고 "내 양을 먹이라"는 새로운 사명을 주셨습니다. 실패한 제자를 목자로 세우시는 놀라운 은혜였습니다.\n\n예수님은 베드로의 미래도 말씀하셨습니다. 젊어서는 스스로 띠를 띠고 다녔지만, 늙어서는 팔을 벌리고 남이 띠를 띠워 원치 않는 곳으로 데려갈 것이라고 하셨습니다. 전승에 의하면 베드로는 후에 로마에서 십자가에 거꾸로 매달려 순교했다고 합니다. 그러나 이제 베드로에게 중요한 것은 다른 제자와 비교하는 것이 아니라 "너는 나를 따르라"는 주님의 부르심에 응답하는 것이었습니다.\n\n요한은 이 모든 일을 목격하고 기록한 증인이었습니다. 그는 예수님이 행하신 일이 너무나 많아서 다 기록한다면 이 세상도 그 책들을 두기에 부족할 것이라고 고백합니다. 복음서는 끝났지만, 부활하신 주님과 함께하는 제자들의 새로운 이야기는 이제 막 시작되고 있었습니다.', E'오늘의 핵심\n부활하신 예수님은 실패와 좌절 속에 있는 제자들의 일상으로 찾아오셔서 그들을 회복시키시고, 새로운 사명을 주셨습니다.\n\n묵상 질문\n1. 내 삶의 실패와 좌절의 자리에서도 주님이 나를 찾아오신다고 믿으시나요?\n2. 베드로처럼 주님께 사랑을 고백하며 회복된 경험이 있으신가요?\n3. "너는 나를 따르라"는 주님의 부르심에 오늘 나는 어떻게 응답하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-06', E'증인이 된 제자들 (사도행전 1장)', E'사도행전 1장', E'부활하신 예수님께서 사십 일 동안 제자들에게 나타나셔서 하나님 나라의 일을 가르치셨습니다. 마지막 만남에서 주님은 제자들에게 예루살렘을 떠나지 말고 아버지께서 약속하신 것을 기다리라고 명하십니다. 그것은 바로 성령의 임하심이었습니다. 제자들은 여전히 이스라엘 나라의 정치적 회복을 기대하고 있었지만, 예수님은 그들에게 더 큰 비전을 제시하십니다. "오직 성령이 너희에게 임하시면 너희가 권능을 받고 예루살렘과 온 유대와 사마리아와 땅 끝까지 이르러 내 증인이 되리라"(행 1:8)는 말씀은 교회의 사명과 방향을 분명히 보여줍니다.\n\n승천하시는 주님을 바라보던 제자들에게 흰 옷 입은 천사들이 나타나 그리스도의 재림을 약속합니다. 감람산에서 예루살렘으로 돌아온 제자들은 다락방에 모여 한마음으로 기도에 전념합니다. 여기에는 열한 사도뿐 아니라 여인들과 예수님의 어머니 마리아, 그리고 예수님의 형제들도 함께했습니다. 약 백이십 명의 무리가 모인 가운데, 베드로가 일어나 가룟 유다를 대신할 사도를 선출하자고 제안합니다. 그들은 요한의 세례 때부터 예수님의 승천까지 함께했던 사람들 중에서 두 사람을 후보로 세우고, 기도 후에 제비를 뽑아 맛디아를 열두 번째 사도로 선택합니다.\n\n이 모든 과정은 초대교회가 어떻게 성령을 기다리며 준비했는지를 보여줍니다. 제자들은 주님의 명령에 순종하여 예루살렘에 머물며, 한마음으로 기도하고, 공동체의 질서를 회복하면서 약속된 성령의 임하심을 기다렸습니다. 이는 교회가 세상을 향해 나아가기 전에 먼저 하나님 앞에서 온전히 준비되어야 함을 가르쳐줍니다.', E'오늘의 핵심\n예수님은 제자들에게 성령을 기다리라고 명하시며, 그들이 예루살렘에서 시작하여 땅 끝까지 이르는 증인의 사명을 감당할 것을 말씀하셨습니다.\n\n묵상 질문\n1. 나는 하나님의 약속을 기다리며 기도로 준비하고 있나요?\n2. 예수님의 증인으로서 내가 서 있는 자리에서 어떻게 복음을 전할 수 있을까요?\n3. 신앙 공동체 안에서 한마음으로 기도하는 일에 얼마나 참여하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-07', E'증인이 된 제자들 (사도행전 2장)', E'사도행전 2장', E'예수님의 승천 후 약속대로 기다리던 제자들에게 마침내 오순절이 이르렀습니다. 유월절로부터 50일째 되는 이날은 유대인의 추수감사절이었는데, 하나님께서는 이날을 영적 추수의 시작점으로 삼으셨습니다. 마가의 다락방에 모여 있던 120명의 성도들에게 급하고 강한 바람 같은 소리와 함께 불의 혀처럼 갈라지는 것이 각 사람 위에 임했습니다. 이것은 구약에서 하나님의 임재를 나타내던 표징들이었습니다. 성령의 충만함을 받은 제자들은 각국의 언어로 하나님의 큰 일을 선포하기 시작했습니다.\n\n오순절 명절을 지키려고 천하 각국에서 모여든 디아스포라 유대인들은 갈릴리 촌사람들이 자기 나라 말로 하나님을 찬양하는 것을 듣고 놀라움을 금치 못했습니다. 바벨탑 사건으로 흩어진 언어가 성령의 역사로 다시 하나가 되는 순간이었습니다. 이때 베드로가 일어나 담대히 설교합니다. 요엘 선지자의 예언이 성취되었음을 선포하며, 너희가 십자가에 못 박은 예수를 하나님이 주와 그리스도가 되게 하셨다고 증언했습니다.\n\n베드로의 설교를 들은 사람들은 마음에 찔림을 받았습니다. "우리가 어찌할꼬"라는 그들의 간절한 질문에 베드로는 회개하고 예수 그리스도의 이름으로 세례를 받으라고 권면합니다. 그날 삼천 명이 세례를 받고 교회의 일원이 되었습니다. 이들은 사도의 가르침을 받아 서로 교제하고, 떡을 떼며, 기도하기를 힘썼습니다. 또한 재산과 소유를 팔아 필요한 사람들과 나누며 초대교회의 아름다운 공동체를 이루었습니다. 성령께서 임하신 결과는 단순히 방언의 은사만이 아니라 사랑의 공동체를 이루는 것이었습니다. 이렇게 예루살렘 교회는 날마다 구원받는 사람이 더해지는 생명력 있는 교회로 성장했습니다.', E'오늘의 핵심\n오순절 성령 강림은 교회 탄생의 시작점이 되었고, 성령의 충만함은 복음 전파의 능력과 사랑의 공동체를 이루는 원동력이 되었습니다.\n\n묵상 질문\n1. 성령의 임재가 제자들을 어떻게 변화시켰는지 묵상해보셨나요?\n2. 초대교회처럼 나눔과 교제가 있는 공동체를 이루기 위해 내가 할 수 있는 일은 무엇일까요?\n3. "우리가 어찌할꼬"라고 묻던 사람들처럼, 나도 회개하고 새롭게 시작해야 할 부분이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-08', E'세워지는 초기교회 (사도행전 3장)', E'사도행전 3장', E'예루살렘 성전은 유대인들의 기도 생활의 중심지였습니다. 제구시, 곧 오후 3시는 유대인들의 정규 기도 시간이었고, 베드로와 요한도 이 시간에 맞추어 성전으로 올라갑니다. 성전 미문에는 태어날 때부터 걷지 못하는 한 사람이 있었습니다. 날마다 이곳에 앉아 성전에 들어가는 사람들에게 구걸하며 살아가던 그에게 베드로와 요한이 다가갑니다.\n\n베드로의 선언은 단순하면서도 강력했습니다. "은과 금은 내게 없거니와 내게 있는 이것을 네게 주노니 나사렛 예수 그리스도의 이름으로 일어나 걸으라"(행 3:6). 물질적인 도움을 기대했던 그 사람은 예상치 못한 선물을 받게 됩니다. 나사렛 예수의 이름으로 선포된 치유의 능력이 그의 발과 발목에 힘을 주었고, 평생 앉아만 있던 그가 뛰어 서서 걷게 되었습니다.\n\n이 놀라운 일을 목격한 백성들이 솔로몬의 행각으로 모여들자, 베드로는 중요한 메시지를 전합니다. 이 기적은 사도들의 개인적 능력이나 경건함 때문이 아니라, 바로 그들이 십자가에 못 박은 예수님의 이름의 능력 때문이라는 것입니다. 베드로는 예수님을 거부하고 죽음에 넘긴 그들의 과거를 상기시키면서도, 하나님께서 죽은 자 가운데서 그를 살리셨다는 부활의 복음을 선포합니다.\n\n특별히 베드로는 그들의 행동이 무지에서 비롯되었음을 인정하면서도, 이제는 회개하고 돌이킬 때임을 강조합니다. 구약의 모든 선지자들이 예언한 그리스도가 바로 예수님이시며, 아브라함에게 약속하신 복이 예수 그리스도를 통해 성취되었다는 것입니다. 하나님께서는 그의 종 예수를 먼저 유대인들에게 보내셔서 그들이 악에서 돌이켜 복을 받게 하셨습니다.\n\n성전 미문의 기적은 단순한 치유 사건이 아니라, 예수 그리스도의 이름이 지닌 능력과 권위를 증명하는 표적이었습니다. 동시에 이스라엘 백성들에게 회개와 믿음으로 나아올 것을 촉구하는 하나님의 은혜로운 초청이었습니다.', E'오늘의 핵심\n예수 그리스도의 이름으로 행해진 치유의 기적은 십자가와 부활의 복음을 증거하는 능력 있는 표적이 되었고, 이를 통해 회개와 믿음의 문이 열렸습니다.\n\n묵상 질문\n1. 물질보다 더 귀한 것을 줄 수 있는 믿음이 내게 있는지 돌아봅시다. 내가 가진 예수님의 이름의 능력을 어떻게 나눌 수 있을까요?\n2. 베드로처럼 담대하게 복음을 전할 기회가 왔을 때, 나는 어떻게 반응하고 있나요?\n3. 하나님께서 내 삶에 행하신 놀라운 일들을 기억하며, 오늘 누구에게 그 은혜를 나눌 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-09', E'세워지는 초기교회 (사도행전 4장)', E'사도행전 4장', E'성전 미문에서 일어난 치유의 기적은 예루살렘 전체를 뒤흔들었습니다. 하루아침에 오천 명이 믿게 되는 놀라운 부흥이 일어났지만, 동시에 종교 지도자들의 격렬한 반대도 시작되었습니다. 제사장들과 성전 맡은 자들, 그리고 부활을 믿지 않는 사두개인들은 사도들이 예수 안에 죽은 자의 부활이 있다고 전하는 것을 견딜 수 없었습니다. 그들은 베드로와 요한을 체포하여 감옥에 가두고, 이튿날 대제사장 안나스와 가야바를 비롯한 최고 권력자들이 모여 심문을 시작했습니다.\n\n"너희가 무슨 권세와 누구의 이름으로 이 일을 행하였느냐"는 그들의 질문 앞에서 베드로는 성령 충만함으로 담대히 선포합니다. 너희가 십자가에 못 박았지만 하나님께서 살리신 나사렛 예수 그리스도의 이름으로 이 사람이 온전하게 되었다고 증언합니다. 더 나아가 베드로는 시편을 인용하며 예수님이 바로 건축자들이 버린 돌이지만 모퉁이의 머릿돌이 되신 분이며, 천하 인간에 구원을 얻을 만한 다른 이름이 없다고 선포합니다.\n\n종교 지도자들은 베드로와 요한의 담대함에 당황했습니다. 그들은 이 두 사람을 본래 학문 없는 평범한 사람으로 알고 있었는데, 지금 보니 전혀 다른 사람들이었습니다. 게다가 치유받은 사람이 함께 서 있으니 부인할 수도 없었습니다. 결국 그들은 예수의 이름으로 말하지도 가르치지도 말라고 위협하며 놓아줄 수밖에 없었습니다. \n\n놓임을 받은 사도들은 동료들에게 돌아가 모든 일을 보고했고, 그들은 한마음으로 하나님께 기도를 올렸습니다. 주님의 종들이 담대히 말씀을 전할 수 있게 해달라고, 예수의 이름으로 표적과 기사가 일어나게 해달라고 간구했습니다. 그 기도가 끝나자 모인 곳이 진동하며 모두가 성령 충만함을 받아 더욱 담대히 하나님의 말씀을 전하게 되었습니다. 이러한 성령의 역사는 공동체의 삶에도 나타났습니다. 믿는 이들이 한마음 한뜻이 되어 모든 물건을 서로 통용하고, 자기 것이라 주장하는 사람이 하나도 없었습니다. 바나바를 비롯한 많은 이들이 자발적으로 재산을 팔아 가난한 이들과 나누었습니다. 이것이 성령께서 인도하시는 초대교회의 아름다운 모습이었습니다.', E'오늘의 핵심\n권력의 위협 앞에서도 성령 충만한 사도들은 예수 그리스도만이 구원자임을 담대히 선포했고, 초대교회는 한마음으로 기도하며 모든 것을 나누는 사랑의 공동체로 성장했습니다.\n\n묵상 질문\n1. 세상의 권세 앞에서도 흔들리지 않는 담대함은 어디에서 오는 것일까요?\n2. 나의 삶에서 예수님의 이름 외에 다른 것에 의지하고 있는 영역은 없나요?\n3. 한마음으로 기도하고 서로 나누는 공동체를 위해 내가 먼저 실천할 수 있는 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-11', E'세워지는 초기교회 (사도행전 5장)', E'사도행전 5장', E'초대교회는 성령의 놀라운 역사 가운데 자라가고 있었습니다. 그러나 교회의 성장과 함께 내부의 어두운 면도 드러나기 시작합니다. 아나니아와 삽비라 부부는 자신들의 소유를 팔아 그 값의 일부를 감추고 나머지만 사도들에게 가져왔습니다. 문제는 그들이 전부를 드린 것처럼 거짓말했다는 것입니다. 베드로는 이들의 거짓을 꿰뚫어보며 "사람에게 거짓말한 것이 아니요 하나님께로다"(행 5:4)라고 선언합니다. 이 사건은 초대교회에 큰 충격과 경외심을 불러일으켰고, 하나님께서 교회의 순결을 얼마나 중요하게 여기시는지를 보여주었습니다.\n\n한편 사도들의 손을 통해 많은 표적과 기사가 일어나자 믿는 자들의 수가 더욱 늘어났고, 심지어 베드로의 그림자라도 병든 자에게 닿기를 바라는 이들이 생겨났습니다. 이러한 부흥의 물결은 종교 지도자들의 시기심을 불러일으켰고, 그들은 사도들을 잡아 옥에 가두었습니다. 그러나 하나님은 천사를 보내어 옥문을 열고 사도들을 이끌어내시며 "가서 성전에 서서 이 생명의 말씀을 다 백성에게 말하라"고 명령하셨습니다.\n\n공회 앞에 선 사도들은 "사람보다 하나님께 순종하는 것이 마땅하니라"고 담대히 선포했습니다. 격분한 종교 지도자들이 사도들을 죽이려 할 때, 존경받는 율법교사 가말리엘이 지혜로운 조언을 합니다. 그는 이 일이 사람에게서 났으면 스스로 무너질 것이요, 하나님께로부터 났으면 막을 수 없을 것이라고 말했습니다. 결국 사도들은 채찍질을 당한 후 풀려났지만, 오히려 그리스도의 이름을 위해 고난받는 것을 영광으로 여기며 기뻐했습니다. 그들은 날마다 성전에서나 집에서나 예수가 그리스도임을 전파하기를 멈추지 않았습니다.', E'오늘의 핵심\n하나님은 교회의 거룩함을 지키시며, 핍박 가운데서도 복음 전파의 사명을 멈추지 않는 사도들을 통해 하나님 나라를 확장하십니다.\n\n묵상 질문\n1. 아나니아와 삽비라처럼 하나님 앞에서 진실하지 못한 모습은 없는지 돌아보셨나요?\n2. "사람보다 하나님께 순종하는 것이 마땅하다"는 말씀이 내 삶에서 어떤 도전을 주나요?\n3. 그리스도를 위한 고난을 기쁨으로 여길 수 있는 믿음을 어떻게 가질 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-12', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 6장)', E'사도행전 6장', E'예루살렘 교회가 성장하면서 교회 내부에 첫 번째 갈등이 발생합니다. 헬라파 유대인들이 히브리파 사람들을 원망하기 시작한 것입니다. 그 이유는 매일 시행되던 구제 사역에서 헬라파 과부들이 소외되고 있었기 때문입니다. 초대교회는 모든 물건을 서로 통용하며 나누는 아름다운 공동체였지만, 교회가 커지면서 구제 사역의 사각지대가 생겨난 것입니다.\n\n사도들은 이 문제를 진지하게 받아들입니다. 그들은 자신들이 구제 사역까지 담당하다 보면 가장 중요한 말씀 사역과 기도에 집중할 수 없음을 깨닫습니다. 그래서 "성령과 지혜가 충만하여 칭찬 받는 사람 일곱"(행 6:3)을 택하여 이 일을 맡기기로 결정합니다. 이는 단순한 업무 분담이 아니라, 각자의 은사에 따라 사역을 나누는 지혜로운 결정이었습니다.\n\n선출된 일곱 집사의 이름을 보면 모두 헬라식 이름을 가진 사람들입니다. 이는 초대교회가 문제를 일으킨 헬라파의 입장을 충분히 고려하여, 그들 가운데서 일꾼을 세웠음을 보여줍니다. 교회는 갈등을 덮거나 무시하지 않고, 소외된 이들의 목소리에 귀를 기울이며 그들을 섬길 사람을 세운 것입니다.\n\n이렇게 일꾼들이 세워지자 놀라운 일이 일어납니다. 하나님의 말씀이 왕성해지고, 예루살렘의 제자 수가 더욱 늘어났으며, 심지어 제사장들까지도 복음에 순종하게 된 것입니다. 스데반은 구제 사역뿐 아니라 은혜와 권능이 충만하여 큰 기사와 표적을 행합니다. 그러나 이러한 능력은 곧 반대자들의 시기와 모함을 불러일으켰고, 거짓 증인들이 그를 모세와 하나님을 모독했다고 고발합니다. \n\n공회 앞에 선 스데반의 얼굴이 천사의 얼굴과 같았다는 것은, 그가 하나님의 임재 가운데 있었음을 보여줍니다. 초대교회는 내부의 갈등을 지혜롭게 해결하여 더욱 성장했지만, 동시에 외부로부터의 박해도 시작되고 있었습니다.', E'오늘의 핵심\n초대교회는 내부 갈등을 은혜롭게 해결하며 각자의 은사에 따라 사역을 분담했고, 이를 통해 교회는 더욱 건강하게 성장할 수 있었습니다.\n\n묵상 질문\n1. 우리 교회나 공동체에서 소외되고 있는 사람들은 누구이며, 그들의 필요에 어떻게 응답하고 있나요?\n2. 나에게 주신 은사를 따라 섬길 수 있는 사역은 무엇일까요?\n3. 갈등이 생길 때 덮어두기보다 지혜롭게 해결하려 노력하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-13', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 7장)', E'사도행전 7장', E'스데반은 산헤드린 공회 앞에서 이스라엘의 역사를 통해 하나님의 구원 계획을 증거합니다. 그의 설교는 아브라함부터 시작하여 족장들, 요셉, 모세를 거쳐 솔로몬 성전에 이르기까지 이스라엘의 전체 역사를 관통합니다. \n\n스데반이 전하는 메시지의 핵심은 하나님께서 언제나 특정한 장소나 건물에 제한되지 않으시고 자유롭게 일하신다는 것입니다. 아브라함은 약속의 땅에서 한 뼘의 땅도 소유하지 못했지만 하나님과 동행했고, 요셉은 애굽에서 노예로 팔렸지만 그곳에서 하나님의 구원 도구가 되었습니다. 모세는 애굽의 왕궁이 아닌 미디안 광야에서 하나님을 만났으며, 이스라엘 백성은 성전이 없는 광야에서도 하나님께 예배드렸습니다.\n\n특별히 스데반은 이스라엘 역사 속에서 반복되는 패턴을 지적합니다. 하나님께서 보내신 지도자들을 백성들이 처음에는 거부했다가 나중에 인정하는 일이 계속되었다는 것입니다. 요셉은 형들에게 미움받아 팔렸고, 모세는 동족에게 "누가 너를 관리와 재판장으로 세웠느냐"라는 거절을 당했습니다. 그러나 하나님은 거절당한 이들을 통해 구원을 이루셨습니다.\n\n스데반의 설교는 단순한 역사 회고가 아닙니다. 그는 조상들이 모세를 거부하고 금송아지를 만들어 우상숭배에 빠졌듯이, 지금 유대 지도자들도 의인이신 예수님을 거부하고 십자가에 못 박았다고 지적합니다. "지극히 높으신 이는 손으로 지은 곳에 계시지 아니하시나니"(행 7:48)라는 선언은 성전 중심의 종교에 안주하면서 정작 성전의 주인이신 하나님과 그의 메시아를 거부한 그들의 모순을 드러냅니다.\n\n이 긴 설교를 통해 스데반은 기독교 신앙이 유대교의 단순한 이단이 아니라, 오히려 아브라함부터 시작된 하나님의 구원 역사의 정당한 계승자임을 증명합니다. 성전과 율법을 넘어서는 하나님의 우주적 통치, 그리고 예수 그리스도를 통한 새로운 구원의 시대가 열렸음을 선포한 것입니다.', E'오늘의 핵심\n스데반은 이스라엘 역사를 통해 하나님께서 특정 장소나 건물에 제한되지 않으시며, 거절당한 자들을 통해 구원을 이루신다는 진리를 증거합니다.\n\n묵상 질문\n1. 내가 하나님을 특정한 장소나 형식 안에 가두려 하지는 않나요?\n2. 하나님께서 보내신 메시지나 사람을 거부한 적은 없었나요?\n3. 신앙의 본질보다 종교적 형식에 안주하고 있지는 않은지 돌아봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-14', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 8장)', E'사도행전 8장', E'예루살렘 교회에 큰 박해가 시작되었습니다. 스데반의 순교 이후, 사울을 비롯한 박해자들은 각 집을 돌며 신자들을 끌어다 옥에 가두었습니다. 사도들을 제외한 대부분의 성도들은 유대와 사마리아 전 지역으로 흩어져야 했습니다. 그러나 놀라운 것은 흩어진 사람들이 도망만 간 것이 아니라 "두루 다니며 복음의 말씀을 전했다"는 사실입니다. 박해가 오히려 복음 전파의 통로가 된 것입니다.\n\n특별히 빌립은 사마리아 성으로 내려가 그리스도를 전파했습니다. 유대인들이 멸시하던 사마리아에 복음이 전해진 것은 하나님 나라의 경계가 확장되는 중요한 전환점이었습니다. 더러운 귀신들이 쫓겨나고 병자들이 치유되면서 그 성에는 큰 기쁨이 충만했습니다. 마술사 시몬까지도 빌립의 사역을 보고 믿음을 고백하며 세례를 받았습니다. 하지만 베드로와 요한이 와서 성령을 받게 하는 안수를 하자, 시몬은 돈으로 그 권능을 사려 했습니다. 베드로는 단호하게 그의 잘못된 동기를 지적하며 회개를 촉구했습니다. 하나님의 은사는 결코 돈으로 살 수 있는 것이 아님을 분명히 보여주는 대목입니다.\n\n이어서 성령께서는 빌립을 광야 길로 인도하셨습니다. 그곳에서 빌립은 예루살렘에서 예배하고 돌아가던 에디오피아 내시를 만났습니다. 내시는 이사야서를 읽고 있었지만 그 의미를 깨닫지 못하고 있었습니다. 빌립은 그가 읽던 바로 그 본문에서 시작하여 예수 그리스도의 복음을 전했습니다. 내시는 즉시 믿음으로 반응하여 세례를 받았고, 기쁨으로 충만하여 자기 길을 갔습니다. 성령께서 빌립을 이끌어 가신 후, 그는 아소도에서부터 가이사랴까지 여러 성을 다니며 계속해서 복음을 전했습니다. 박해로 인한 흩어짐이 오히려 예루살렘을 넘어 유대와 사마리아, 그리고 이방 땅끝까지 복음이 전파되는 하나님의 섭리가 되었던 것입니다.', E'오늘의 핵심\n예루살렘 교회의 박해와 흩어짐은 오히려 복음이 사마리아와 이방인에게까지 전파되는 하나님의 섭리가 되었습니다.\n\n묵상 질문\n1. 내 삶의 어려움과 흩어짐이 오히려 복음 전파의 기회가 될 수 있을까요?\n2. 하나님의 은사를 세상적 방법으로 얻으려 한 적은 없나요?\n3. 말씀을 갈급해하는 영혼을 만날 때 복음을 전할 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-15', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 9장)', E'사도행전 9장', E'초대교회를 향한 박해의 선봉에 섰던 사울의 이야기가 사도행전 9장에 펼쳐집니다. "주의 제자들에 대하여 여전히 위협과 살기가 등등하여"(행 9:1) 대제사장에게서 공문을 받아 다메섹으로 향하던 사울은, 그 길에서 부활하신 예수님을 만나게 됩니다. 홀연히 하늘로부터 비춘 빛과 함께 들려온 음성은 사울의 인생을 완전히 뒤바꾸어 놓았습니다.\n\n주님께서는 사울에게 "네가 어찌하여 나를 박해하느냐"고 물으셨는데, 이는 교회를 박해하는 것이 곧 그리스도를 박해하는 것임을 보여줍니다. 교회는 그리스도의 몸이며, 성도 한 사람 한 사람이 주님과 연합되어 있다는 놀라운 진리가 여기에 담겨 있습니다. \n\n사울은 사흘 동안 앞을 보지 못하고 먹지도 마시지도 못한 채 어둠 속에 머물렀습니다. 이 시간은 단순한 신체적 고통의 시간이 아니라, 자신의 과거를 돌아보고 새로운 부르심을 받아들이는 영적 전환의 시간이었습니다. 한편 아나니아는 두려움 속에서도 주님의 명령에 순종하여 사울을 찾아갑니다. 박해자였던 사울을 "형제"라 부르며 안수하는 아나니아의 모습은 용서와 화해의 복음이 무엇인지를 보여줍니다.\n\n회심한 사울은 즉시 회당에서 예수가 하나님의 아들이심을 전파하기 시작했습니다. 한때 교회를 핍박하던 자가 이제는 복음을 전하는 자가 된 것입니다. 이러한 극적인 변화는 유대인들을 당혹하게 만들었고, 급기야 그들은 사울을 죽이려는 음모를 꾸미게 됩니다. 박해자에서 피박해자가 된 사울의 모습은 복음의 능력이 얼마나 강력한지를 증거합니다.\n\n예루살렘 교회는 처음에 사울을 받아들이기를 주저했습니다. 그러나 바나바가 중재자로 나서서 사울의 회심을 증언했고, 이를 통해 사울은 사도들과 교제를 나눌 수 있게 되었습니다. 바나바의 이러한 역할은 교회 공동체 안에서 화해와 신뢰를 세워가는 일이 얼마나 중요한지를 가르쳐 줍니다. 하나님께서는 교회의 가장 큰 박해자를 이방인의 사도로 변화시키셨고, 이를 통해 복음이 온 세계로 퍼져나가는 새로운 장을 열어가셨습니다.', E'오늘의 핵심\n교회를 박해하던 사울이 부활하신 예수님을 만나 회심함으로써, 하나님께서는 가장 강력한 반대자를 가장 열정적인 복음 전파자로 변화시키셨습니다.\n\n묵상 질문\n1. 내가 거부하고 있는 하나님의 부르심은 없는지 돌아보셨나요?\n2. 과거의 실패와 죄가 하나님의 은혜로 어떻게 변화될 수 있을까요?\n3. 바나바처럼 화해의 다리 역할을 감당해야 할 상황이 있다면 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-16', E'베드로와 고넬료의 만남 (사도행전 10장)', E'사도행전 10장', E'가이사랴에 주둔한 로마 백부장 고넬료는 이방인이었지만 하나님을 경외하는 경건한 사람이었습니다. 그가 기도하던 중 하나님의 사자가 나타나 베드로를 청하라는 지시를 받습니다. 동시에 욥바에서 기도하던 베드로에게도 하늘에서 내려온 보자기에 담긴 각종 짐승들을 보는 환상이 주어집니다. 유대인으로서 부정한 것을 먹을 수 없다고 거부하는 베드로에게 "하나님께서 깨끗하게 하신 것을 네가 속되다 하지 말라"(행 10:15)는 음성이 들립니다.\n\n이 환상의 의미를 깨닫지 못하던 베드로에게 고넬료가 보낸 사람들이 도착합니다. 성령의 인도하심을 따라 베드로는 그들과 함께 가이사랴로 향합니다. 로마의 백부장이 유대인 앞에 엎드려 절하는 놀라운 광경이 펼쳐집니다. 베드로는 비로소 깨닫습니다. 하나님께서는 사람의 외모를 보지 않으시고, 각 나라 중 하나님을 경외하며 의를 행하는 사람은 누구든지 받으신다는 것을 말입니다.\n\n베드로가 예수 그리스도의 복음을 전할 때, 놀라운 일이 일어납니다. 성령께서 말씀을 듣는 모든 이방인들에게 임하신 것입니다. 할례받은 유대인 신자들은 이방인들이 방언을 말하며 하나님을 높이는 것을 보고 놀랐습니다. 이것은 오순절 성령 강림이 이방인에게도 동일하게 일어난 것입니다. 베드로는 즉시 그들에게 세례를 베풀도록 명합니다.\n\n하나님께서는 베드로와 고넬료의 만남을 통해 구원의 문이 모든 민족에게 열렸음을 선포하십니다. 유대인의 선민의식과 이방인을 향한 편견의 장벽이 성령의 역사로 무너집니다. 교회는 이제 민족과 문화의 경계를 넘어 하나님 나라의 보편성을 깨닫게 되었습니다.', E'오늘의 핵심\n하나님께서는 베드로의 환상과 고넬료와의 만남을 통해 복음이 모든 민족을 위한 것임을 선포하시고, 성령의 은사로 이를 확증하십니다.\n\n묵상 질문\n1. 내가 가진 신앙의 편견이나 선입견은 무엇이며, 하나님께서 이를 어떻게 깨뜨리기 원하실까요?\n2. 고넬료처럼 하나님을 간절히 찾는 사람들에게 복음을 전할 준비가 되어 있나요?\n3. 성령께서는 민족과 문화의 장벽을 넘어 역사하시는데, 나는 어떤 열린 마음으로 하나님의 일하심에 동참할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-18', E'베드로와 고넬료의 만남 (사도행전 11장)', E'사도행전 11장', E'초대교회 역사의 중요한 전환점이 사도행전 11장에 기록되어 있습니다. 베드로가 이방인 고넬료의 집을 방문하고 그들에게 세례를 베푼 소식이 예루살렘에 전해지자, 할례받은 유대인 신자들이 베드로를 비난합니다. 그들에게는 이방인과 함께 먹는다는 것이 율법을 어기는 심각한 일이었기 때문입니다. 베드로는 차분히 자신이 경험한 환상과 성령의 역사를 차례대로 설명합니다. 하늘에서 내려온 보자기에 담긴 부정한 짐승들, 그리고 "하나님이 깨끗하게 하신 것을 네가 속되다 하지 말라"는 음성이 세 번이나 반복되었음을 증언합니다.\n\n베드로의 설명 중 가장 결정적인 부분은 이방인들에게도 성령이 임하셨다는 사실입니다. 오순절에 유대인들이 받았던 것과 동일한 성령의 은사를 이방인들도 받았다는 것은 하나님께서 그들을 동등하게 받아주셨다는 명백한 증거였습니다. 이 증언을 들은 예루살렘 교회는 침묵했다가 마침내 하나님께 영광을 돌리며 "하나님께서 이방인에게도 생명 얻는 회개를 주셨도다"라고 고백합니다. 이는 교회사의 획기적인 순간으로, 복음이 유대인의 울타리를 넘어 온 세상으로 확산되는 문이 공식적으로 열린 것입니다.\n\n한편 스데반의 순교로 흩어진 신자들 중 일부는 안디옥에 이르러 헬라인들에게도 복음을 전했고, 놀랍게도 수많은 사람이 주께 돌아왔습니다. 예루살렘 교회는 바나바를 파송하여 이 일을 살피게 했는데, 바나바는 그곳에서 하나님의 은혜를 목격하고 크게 기뻐했습니다. 더 나아가 그는 다소에 있던 사울을 찾아가 안디옥으로 데려와 함께 사역했습니다. 이렇게 안디옥 교회는 이방인 선교의 전진기지가 되었고, 제자들이 처음으로 ''그리스도인''이라 불리게 된 역사적인 장소가 되었습니다. 교회는 민족과 문화의 장벽을 넘어 그리스도 안에서 하나 되는 공동체로 성장해 나갔습니다.', E'오늘의 핵심\n하나님께서는 성령의 역사를 통해 이방인도 구원의 대상임을 분명히 보여주셨고, 초대교회는 이를 인정하며 복음의 보편성을 받아들였습니다.\n\n묵상 질문\n1. 나에게도 깨뜨려야 할 편견의 장벽이 있다면 무엇인가요?\n2. 하나님의 은혜가 내 생각보다 훨씬 넓고 깊다는 것을 경험한 적이 있나요?\n3. 복음 안에서 ''다름''을 인정하고 함께 하나 되는 공동체를 어떻게 만들어갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-19', E'베드로와 고넬료의 만남 (사도행전 12장)', E'사도행전 12장', E'초대교회를 향한 핍박의 손길이 더욱 거세지고 있었습니다. 헤롯 아그립바 1세가 교회를 탄압하기 시작하면서 요한의 형제 야고보를 칼로 죽였고, 이것이 유대인들에게 호응을 얻자 베드로마저 체포했습니다. 무교절 기간이었기에 헤롯은 유월절이 끝난 후 베드로를 백성 앞에서 처형하려고 계획했습니다. 네 명씩 네 패의 군인들이 삼엄하게 베드로를 지키고 있었지만, 교회는 그를 위해 간절히 기도했습니다.\n\n베드로가 처형되기 전날 밤, 놀라운 일이 일어났습니다. 주의 천사가 나타나 쇠사슬에 묶여 있던 베드로를 깨우고, 삼엄한 경비를 뚫고 그를 감옥 밖으로 인도했습니다. 베드로는 처음에 이것이 환상인 줄 알았으나, 거리로 나왔을 때 비로소 하나님께서 자신을 구원하신 것을 깨달았습니다. 그는 곧바로 마가 요한의 어머니 마리아의 집으로 갔는데, 그곳에서는 많은 성도들이 모여 기도하고 있었습니다. \n\n흥미롭게도 간절히 기도하던 그들은 정작 베드로가 문을 두드렸을 때 믿지 못했습니다. 로데라는 여종이 베드로의 음성을 알아듣고 기뻐하며 전했지만, 사람들은 그녀가 미쳤다고 여겼습니다. 이는 우리의 기도 생활을 돌아보게 합니다. 간절히 기도하면서도 정작 응답이 왔을 때 믿지 못하는 우리의 연약한 믿음을 보여줍니다.\n\n한편 베드로를 잃어버린 헤롯은 파수꾼들을 처형하고 가이사랴로 내려갔습니다. 그곳에서 두로와 시돈 사람들 앞에서 연설할 때, 백성들이 "이것은 신의 소리요 사람의 소리가 아니라"고 외쳤습니다. 헤롯이 이 영광을 하나님께 돌리지 않자, 주의 사자가 그를 쳐서 벌레에게 먹혀 죽게 했습니다. 교회를 핍박하던 헤롯은 비참한 최후를 맞았지만, "하나님의 말씀은 흥왕하여 더하더라"(행 12:24)고 성경은 기록합니다. 하나님의 나라는 어떤 박해와 위협 속에서도 전진하며 확장되어 갑니다.', E'오늘의 핵심\n하나님께서는 기도하는 교회를 통해 일하시며, 교회를 핍박하는 자들의 교만을 꺾으시고 복음이 계속 전파되도록 역사하십니다.\n\n묵상 질문\n1. 내가 간절히 기도하면서도 정작 응답을 의심하거나 놓친 적은 없나요?\n2. 어려운 상황 속에서도 함께 모여 기도하는 공동체의 힘을 경험해 보셨나요?\n3. 헤롯처럼 하나님께 돌려야 할 영광을 가로채려는 교만한 마음은 없는지 돌아볼까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-20', E'1차 전도여행과 예루살렘 공의회 (사도행전 13장)', E'사도행전 13장', E'안디옥 교회가 예배하며 금식할 때, 성령께서 직접 바나바와 사울을 따로 세우라고 말씀하십니다. 교회는 이 음성에 순종하여 두 사람에게 안수하고 보내줍니다. 여기서 주목할 점은, 안디옥 교회가 자기 교회의 핵심 인물들을 선뜻 내어놓았다는 것입니다. 바나바와 사울은 교회에 꼭 필요한 선지자이자 교사였지만, 교회는 성령의 인도하심 앞에서 붙잡지 않았습니다. 이것이 1차 전도여행의 출발점이 됩니다.\n\n바울 일행은 처음에 유대인 회당을 중심으로 복음을 전합니다. 구브로 섬에서 총독 서기오 바울을 만나게 되는데, 마술사 엘루마가 방해하자 바울은 성령의 능력으로 그를 맹인이 되게 합니다. 이 사건을 통해 총독은 주의 가르치심을 놀랍게 여기며 믿게 됩니다. 복음은 영적 대적을 물리치며 전진하는 하나님의 능력임을 보여줍니다.\n\n비시디아 안디옥 회당에서 바울은 이스라엘의 역사를 쭉 훑으며 그 모든 이야기가 결국 예수 그리스도를 향하고 있음을 선포합니다. 애굽에서의 구원, 광야에서의 인도, 가나안 정착, 사사와 왕들의 역사를 거쳐 다윗에게서 나신 구주 예수님께 이르는 구원사의 정점을 제시합니다. 핵심은 38-39절입니다. "이 사람을 힘입어 죄 사함을 너희에게 전하는 이것이며, 또 모세의 율법으로 너희가 의롭다 하심을 얻지 못하던 모든 일에도 이 사람을 힘입어 믿는 자마다 의롭다 하심을 얻는 이것이라." 율법의 행위가 아니라 예수를 믿는 믿음으로 의롭게 된다는 복음의 본질이 여기서 분명히 선언됩니다.\n\n그런데 다음 안식일 온 도시가 모여들자 유대인들은 시기하여 바울의 말을 반박하고 비방합니다. 이에 바울과 바나바는 담대히 선언합니다. 하나님의 말씀을 먼저 유대인에게 전했으나 그들이 거부했으므로 이제 이방인에게로 향한다는 것입니다. 이방인들은 이 말을 듣고 기뻐하며 하나님의 말씀을 찬송합니다. 복음은 민족과 신분의 경계를 넘어 모든 믿는 자에게 구원을 주시는 하나님의 은혜임을 보여줍니다.', E'오늘의 핵심\n성령의 인도하심을 따라 시작된 바울의 선교는 율법이 아닌 믿음으로 의롭게 된다는 복음을 선포하며, 유대인의 거부로 인해 이방인에게로 향하게 됩니다.\n\n묵상 질문\n1. 내가 붙잡고 있는 것을 성령의 인도하심 앞에 내려놓을 준비가 되어 있나요?\n2. 율법의 행위가 아닌 믿음으로 의롭다 함을 받는다는 복음을 참으로 신뢰하고 있나요?\n3. 복음을 거부하는 이들 앞에서도 담대히 하나님의 은혜를 전할 용기가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-21', E'1차 전도여행과 예루살렘 공의회 (사도행전 14장)', E'사도행전 14장', E'이고니온에서 바울과 바나바가 회당에서 말씀을 전하자 유대인과 헬라인의 허다한 무리가 믿게 되었습니다. 그러나 믿지 않는 유대인들이 이방인들의 마음을 선동하여 사도들에 대한 악감을 품게 했습니다. 두 사도는 이런 반대에도 불구하고 오랫동안 머물며 담대히 복음을 전했고, 주님께서는 표적과 기사로 은혜의 말씀을 증거하셨습니다. 결국 도시 전체가 나뉘어 충돌이 일어나자 두 사도는 루가오니아 지방으로 피신하게 됩니다.\n\n루스드라에서는 놀라운 일이 벌어집니다. 나면서부터 걷지 못한 사람이 바울의 설교를 듣고 있었는데, 바울이 그에게서 구원받을 만한 믿음을 보고 "네 발로 바로 일어서라"고 명하자 그가 일어나 걷게 된 것입니다. 그런데 이 기적이 예상치 못한 방향으로 흘러갑니다. 사람들이 바나바를 제우스로, 바울을 헤르메스로 여기며 제사를 드리려 한 것입니다. 두 사도는 옷을 찢으며 급히 말렸고, 자신들도 똑같은 사람임을 분명히 하면서 오직 살아계신 하나님께로 돌아오라고 외쳤습니다.\n\n복음 전파의 길은 순탄하지 않았습니다. 안디옥과 이고니온에서 온 유대인들이 무리를 충동하여 바울을 돌로 쳐서 성 밖에 버렸습니다. 죽은 줄로 알았지만 제자들이 둘러섰을 때 바울은 다시 일어났고, 놀랍게도 다시 그 성으로 들어갔습니다. 이후 바울과 바나바는 더베에서 복음을 전한 후, 왔던 길을 되돌아가며 각 도시의 제자들을 굳게 세웠습니다. "우리가 하나님의 나라에 들어가려면 많은 환난을 겪어야 할 것이라"는 바울의 말은 그가 직접 경험한 진실이었습니다.\n\n안디옥 교회로 돌아온 두 사도는 하나님께서 이방인들에게 믿음의 문을 여신 일들을 보고했습니다. 돌에 맞아 죽을 뻔한 위기도, 신으로 추앙받는 혼란도, 모든 것이 복음이 전파되는 과정이었습니다. 하나님의 은혜는 인간의 반대와 오해를 뚫고 계속해서 앞으로 나아갔습니다.', E'오늘의 핵심\n복음은 격렬한 반대와 극단적인 오해 속에서도 전진했으며, 바울은 환난을 통과하며 하나님 나라에 들어가는 길을 몸소 보여주었습니다.\n\n묵상 질문\n1. 내가 복음을 전할 때 만나는 반대나 오해를 어떻게 받아들이고 있나요?\n2. 환난 속에서도 다시 일어나 그 자리로 돌아간 바울의 담대함은 어디서 왔을까요?\n3. 하나님의 은혜가 내 삶의 어려움을 어떻게 돌파하고 계신지 돌아볼 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-22', E'1차 전도여행과 예루살렘 공의회 (사도행전 15장)', E'사도행전 15장', E'유대로부터 내려온 어떤 사람들이 안디옥 교회에 심각한 논쟁을 일으킵니다. 그들은 이방인 신자들도 모세의 법대로 할례를 받아야만 구원받을 수 있다고 주장했습니다. 이것은 단순한 의견 차이가 아니라 복음의 본질에 관한 문제였습니다. 바울과 바나바는 이들과 격렬히 논쟁했고, 결국 이 문제를 해결하기 위해 예루살렘으로 가게 됩니다.\n\n예루살렘 공의회에서는 초대교회 역사상 가장 중요한 결정이 내려집니다. 베드로는 하나님께서 이미 고넬료의 집에서 이방인들에게도 성령을 주셨음을 상기시킵니다. 그는 "우리는 그들이 우리와 동일하게 주 예수의 은혜로 구원 받는 줄을 믿노라"(행 15:11)고 선언합니다. 야고보도 구약의 예언을 인용하며 이방인들이 하나님의 백성이 되는 것이 하나님의 계획임을 확증합니다.\n\n공의회의 결정은 복음의 보편성을 분명히 보여줍니다. 이방인들에게 할례나 율법의 무거운 짐을 지우지 않기로 했습니다. 다만 우상숭배와 음행, 그리고 유대인들과의 교제를 위한 최소한의 요구사항만을 제시합니다. 이는 구원이 오직 은혜로 말미암음을 확증하면서도, 믿음의 공동체 안에서 서로를 배려하는 지혜로운 결정이었습니다.\n\n하지만 이 장의 끝에서 우리는 뜻밖의 장면을 목격합니다. 그토록 든든한 동역자였던 바울과 바나바가 마가 요한 문제로 심히 다투어 헤어지게 됩니다. 바나바는 실패했던 마가에게 다시 기회를 주고자 했고, 바울은 사역의 신실함을 더 중요하게 여겼습니다. 이 갈등은 완벽해 보이는 초대교회도 인간적 연약함을 가지고 있었음을 보여줍니다. 그러나 하나님께서는 이 아픈 분열마저도 선교의 확장으로 사용하셨습니다. 바나바는 마가와 함께 구브로로, 바울은 실라와 함께 새로운 지역으로 나아가게 됩니다.', E'오늘의 핵심\n예루살렘 공의회는 구원이 오직 예수 그리스도의 은혜로 받는다는 복음의 핵심을 확증했고, 하나님께서는 인간의 갈등마저도 복음 전파의 도구로 사용하십니다.\n\n묵상 질문\n1. 내가 다른 사람에게 복음 외에 불필요한 짐을 지우고 있지는 않은가요?\n2. 의견이 다른 동역자와 갈등할 때, 하나님의 더 큰 계획을 신뢰할 수 있나요?\n3. 실패한 사람을 다시 세우는 바나바의 마음과 사명에 충실한 바울의 마음 중 나는 어느 쪽에 더 가깝나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-23', E'2차 전도여행 (사도행전 16장)', E'사도행전 16장', E'바울의 2차 전도여행은 예상치 못한 만남과 인도하심으로 시작됩니다. 더베와 루스드라에서 바울은 디모데라는 젊은 제자를 만나게 되는데, 그는 믿는 유대인 어머니와 헬라인 아버지 사이에서 태어난 사람이었습니다. 바울이 그를 데리고 가면서 할례를 행한 것은 복음 전파에 걸림돌이 되지 않기 위한 목회적 배려였습니다. 이들이 여러 교회를 방문하며 예루살렘 공의회의 결정사항을 전달하자, 교회들은 믿음이 더욱 굳건해지고 날마다 성장하게 됩니다.\n\n그런데 바울의 계획과 달리 성령께서는 아시아에서 말씀을 전하지 못하게 막으셨고, 비두니아로 가려는 시도도 예수의 영이 허락하지 않으셨습니다. 드로아에서 바울이 본 마게도냐 사람의 환상은 하나님께서 유럽 선교의 문을 여시는 결정적인 전환점이 됩니다. 이렇게 복음은 아시아를 넘어 유럽 대륙으로 향하게 되었습니다.\n\n빌립보에서의 사역은 강가의 기도처에서 시작되었습니다. 자색 옷감 장사 루디아의 마음을 주께서 열어주셔서 바울의 말씀을 받아들이게 하셨고, 그녀와 온 집안이 세례를 받아 유럽 최초의 그리스도인이 됩니다. 그러나 점치는 귀신 들린 여종을 고친 일로 바울과 실라는 매를 맞고 깊은 옥에 갇히게 됩니다.\n\n한밤중 감옥에서 울려 퍼진 바울과 실라의 기도와 찬송은 놀라운 기적을 일으킵니다. 지진으로 옥문이 열렸으나 아무도 도망가지 않았고, 자결하려던 간수는 오히려 "내가 어떻게 하여야 구원을 받으리이까"라고 묻게 됩니다. 그 밤 간수와 온 가족이 세례를 받고 구원의 기쁨을 누리게 되었습니다. 고난 가운데서도 하나님께서는 복음의 능력을 나타내시고, 구원받을 영혼들을 예비하고 계셨던 것입니다.', E'오늘의 핵심\n성령의 인도하심을 따라 유럽으로 향한 바울은 빌립보에서 극심한 고난 속에서도 찬양하며, 간수의 가정에 구원의 역사를 일으킵니다.\n\n묵상 질문\n1. 내 계획과 달리 막히는 길이 있을 때, 그것이 더 큰 하나님의 계획을 위한 인도하심은 아닐까요?\n2. 고난의 한밤중에도 기도와 찬송을 드릴 수 있는 믿음이 내게 있나요?\n3. 루디아와 간수처럼 온 가족이 함께 믿음으로 나아가기 위해 내가 할 수 있는 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-25', E'2차 전도여행 (사도행전 17장)', E'사도행전 17장', E'바울의 두 번째 전도여행은 예상과는 다른 방향으로 전개되고 있었습니다. 데살로니가에서 바울은 자신의 관례대로 회당에 들어가 세 안식일 동안 성경을 가지고 강론합니다. 그의 메시지는 명확했습니다. 그리스도께서 고난을 받으시고 죽은 자 가운데서 부활하셔야 한다는 것, 그리고 이 예수님이 바로 그 그리스도라는 것이었습니다. 이 복음은 경건한 헬라인들과 귀부인들의 마음을 움직였지만, 유대인들의 시기심을 불러일으켰습니다. 그들은 폭도들을 동원해 도시를 소란케 하고, 바울 일행을 맞아들인 야손의 집을 습격했습니다. "천하를 어지럽게 하던 이 사람들"이라는 그들의 고발은 역설적으로 복음의 능력을 증명하는 것이었습니다.\n\n베뢰아 사람들의 반응은 데살로니가와는 대조적이었습니다. 그들은 더 너그러운 마음으로 말씀을 받았을 뿐 아니라, 날마다 성경을 상고하며 바울의 가르침이 진리인지 확인했습니다. 이러한 열린 자세와 성경 중심의 태도는 많은 이들을 믿음으로 인도했습니다. 그러나 데살로니가의 유대인들이 베뢰아까지 와서 소동을 일으키자, 바울은 아덴으로 떠나야 했습니다.\n\n철학의 도시 아덴에서 바울은 전혀 다른 청중을 만났습니다. 도시 곳곳에 가득한 우상들을 보며 마음에 격분한 바울은 회당뿐 아니라 장터에서도 복음을 전했습니다. 에피쿠로스와 스토아 철학자들은 그를 "말쟁이"라고 조롱했지만, 동시에 그의 새로운 가르침에 호기심을 보였습니다. 아레오바고에서의 설교는 바울의 지혜로운 복음 전도 방법을 보여줍니다. 그는 "알지 못하는 신"이라는 제단을 출발점으로 삼아, 창조주 하나님과 그분 안에서의 인간의 정체성, 그리고 부활하신 그리스도를 통한 심판의 메시지를 전했습니다. 청중의 반응은 엇갈렸지만, 아레오바고 관리 디오누시오와 다마리를 비롯한 몇 사람은 믿음을 갖게 되었습니다.', E'오늘의 핵심\n바울은 각 지역의 상황과 청중에 맞춰 복음을 전하되, 십자가와 부활의 핵심 메시지는 결코 타협하지 않았습니다.\n\n묵상 질문\n1. 베뢰아 사람들처럼 날마다 성경을 상고하며 진리를 확인하는 자세를 갖추고 있나요?\n2. 복음이 "천하를 어지럽게 한다"는 고발이 오늘날 우리에게는 어떤 의미일까요?\n3. 바울처럼 다양한 사람들에게 지혜롭게 복음을 전하려면 어떤 준비가 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-26', E'2차 전도여행 (사도행전 18장)', E'사도행전 18장', E'바울이 아덴을 떠나 고린도에 도착했을 때, 그곳에서 아굴라와 브리스길라 부부를 만나게 됩니다. 로마 황제 글라우디오의 유대인 추방령으로 인해 이탈리아에서 새로 온 이들과 바울은 같은 천막 제조업에 종사하며 함께 생활하게 되었습니다. 생업을 통해 자비량 선교를 감당하면서도 안식일마다 회당에서 복음을 전하는 바울의 모습은, 복음 전파자의 균형 잡힌 삶의 자세를 보여줍니다.\n\n실라와 디모데가 마게도냐로부터 도착하자, 바울은 더욱 말씀에 붙잡혀 예수가 그리스도이심을 힘있게 증언합니다. 그러나 유대인들의 강한 반대에 직면하자, 바울은 이방인 선교로 방향을 전환합니다. 회당장 그리스보와 많은 고린도 사람들이 복음을 받아들이고 세례를 받는 놀라운 일이 일어났습니다. 특히 주님께서 환상 중에 "두려워하지 말며 침묵하지 말고 말하라"(행 18:9)고 격려하시며, 이 성중에 주의 백성이 많음을 알려주신 것은 바울에게 큰 위로와 확신이 되었습니다.\n\n고린도에서 1년 6개월이라는 긴 시간 동안 말씀을 가르친 바울은, 갈리오 총독 앞에서 고발당하지만 오히려 보호받게 됩니다. 종교적 문제에 개입하지 않겠다는 갈리오의 판결은 복음 전파에 유리한 환경을 조성해 주었습니다. 이후 바울은 브리스길라와 아굴라와 함께 에베소로 향했고, 그곳에서 잠시 머문 후 예루살렘을 거쳐 안디옥으로 돌아갑니다.\n\n한편 알렉산드리아 출신의 아볼로가 에베소에서 열심히 가르치고 있었는데, 브리스길라와 아굴라가 그에게 하나님의 도를 더 정확하게 가르쳐 주었습니다. 이는 평신도 부부가 탁월한 설교자를 겸손히 인도하는 아름다운 동역의 모습을 보여줍니다. 아볼로는 이후 아가야로 건너가 은혜로 믿은 자들에게 큰 유익을 주며, 성경으로써 예수가 그리스도이심을 힘있게 증언했습니다.', E'오늘의 핵심\n고린도에서의 사역은 동역자들과의 만남, 주님의 직접적인 격려, 그리고 로마 정부의 보호라는 삼중의 은혜 가운데 풍성한 열매를 맺게 되었습니다.\n\n묵상 질문\n1. 바울이 천막 제조업을 하며 복음을 전한 것처럼, 나는 일상의 삶과 신앙을 어떻게 조화시키고 있나요?\n2. 주님께서 "두려워하지 말고 말하라"고 하신 말씀이 오늘 나에게는 어떤 의미로 다가오나요?\n3. 브리스길라와 아굴라처럼 다른 사람의 신앙 성장을 돕는 겸손한 동역자가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-27', E'마지막 예루살렘 방문 (사도행전 20장)', E'사도행전 20장', E'바울이 3차 선교여행을 마무리하며 예루살렘으로 향하는 여정은 결코 순탄하지 않았습니다. 유대인들의 해하려는 공모로 계획된 항로를 바꿔야 했고, 성령께서는 각 성에서 결박과 환난이 기다린다고 증언하셨습니다. 그럼에도 바울의 발걸음은 멈추지 않았습니다. 오히려 "내가 달려갈 길과 주 예수께 받은 사명 곧 하나님의 은혜의 복음을 증언하는 일을 마치려 함에는 나의 생명조차 조금도 귀한 것으로 여기지 아니하노라"(행 20:24)고 고백합니다.\n\n밀레도에서 에베소 교회 장로들을 불러 전한 바울의 고별 설교는 한 사역자의 삶 전체가 담긴 유언과 같았습니다. 그는 모든 겸손과 눈물로 주를 섬겼고, 유익한 것은 무엇이든지 거리낌 없이 전했으며, 하나님의 뜻을 다 전하는 일에 꺼리지 않았다고 증언합니다. 특별히 바울은 자신의 손으로 일하며 약한 사람들을 도왔고, "주는 것이 받는 것보다 복이 있다"는 주님의 말씀을 몸소 실천했습니다.\n\n이 고별의 순간에서 가장 인상적인 것은 바울과 장로들 사이의 깊은 사랑입니다. 3년 동안 밤낮 쉬지 않고 눈물로 각 사람을 훈계했던 바울의 헌신은 장로들의 마음을 움직였고, 그들은 크게 울며 바울의 목을 안고 입을 맞췄습니다. 이는 단순한 목회자와 교인의 관계를 넘어선, 복음 안에서 맺어진 깊은 영적 가족의 모습을 보여줍니다.\n\n드로아에서 밤새 말씀을 전하다가 유두고가 창에서 떨어져 죽은 사건은 또 다른 교훈을 줍니다. 바울은 당황하지 않고 청년을 안으며 생명이 있다고 선언했고, 실제로 그는 살아났습니다. 이 놀라운 기적 후에도 바울은 날이 새도록 계속해서 말씀을 전했습니다. 복음 전파에 대한 그의 열정은 어떤 상황에서도 식지 않았습니다.\n\n오늘 우리도 각자의 자리에서 달려갈 길이 있습니다. 때로는 유대인들의 공모처럼 예상치 못한 방해가 있을 수 있고, 앞날에 대한 불확실함이 우리를 주저하게 만들 수도 있습니다. 그러나 바울이 보여준 것처럼, 주님께 받은 사명이 분명하다면 우리는 담대히 나아갈 수 있습니다. 하나님의 은혜의 말씀이 우리를 능히 든든히 세우실 것입니다.', E'오늘의 핵심\n바울은 앞에 놓인 결박과 환난을 알면서도 하나님의 은혜의 복음을 증언하는 사명을 완수하기 위해 생명조차 아끼지 않고 예루살렘으로 향했습니다.\n\n묵상 질문\n1. 바울이 위험을 알면서도 예루살렘으로 향한 이유는 무엇이며, 나에게도 그런 사명이 있을까요?\n2. 바울처럼 눈물로 섬기며 복음을 전하는 삶을 살기 위해 내가 내려놓아야 할 것은 무엇일까요?\n3. "주는 것이 받는 것보다 복이 있다"는 말씀을 오늘 내 삶에서 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-28', E'마지막 예루살렘 방문 (사도행전 21장)', E'사도행전 21장', E'바울의 예루살렘 행은 성령의 경고와 동역자들의 만류 속에서도 계속됩니다. 두로에서 제자들은 성령의 감동으로 바울에게 예루살렘에 들어가지 말라고 권면했고, 가이사랴에서는 아가보 선지자가 바울의 띠로 자기 손발을 묶으며 체포를 예언했습니다. 그러나 바울의 대답은 단호했습니다. "나는 주 예수의 이름을 위하여 결박 당할 뿐 아니라 예루살렘에서 죽을 것도 각오하였노라"(행 21:13). 이는 맹목적인 고집이 아니라 부르신 이를 향한 깊은 신뢰에서 나온 결단이었습니다.\n\n예루살렘에 도착한 바울은 야고보와 장로들을 만나 이방인 선교의 열매들을 나누었습니다. 하지만 유대인 신자들 사이에서는 바울이 모세를 배반하고 할례와 관습을 버리라고 가르친다는 오해가 퍼져 있었습니다. 바울은 화평을 위해 결례를 행하며 율법도 존중함을 보여주려 했습니다. 그러나 아시아에서 온 유대인들이 바울을 보자 성전을 더럽혔다는 거짓 고발로 군중을 선동했고, 온 예루살렘이 소동에 휩싸입니다.\n\n바울이 군중에게 죽을 위기에 처했을 때, 하나님의 섭리는 로마 천부장의 개입으로 나타납니다. 소동의 소식을 들은 천부장이 군인들을 이끌고 달려와 바울을 체포함으로써 오히려 그의 생명을 구했습니다. 바울은 자신이 길리기아 다소의 시민임을 밝히고 백성들에게 변호할 기회를 얻습니다. 이 모든 과정은 복음이 예루살렘에서 로마까지 전파되도록 인도하시는 하나님의 더 큰 계획 안에 있었습니다.\n\n우리도 때로는 하나님의 뜻을 따르는 길에서 반대와 오해에 직면합니다. 주변의 만류가 사랑에서 나온 것일지라도, 하나님께서 주신 확실한 부르심이 있다면 믿음으로 나아가야 할 때가 있습니다. 바울이 보여준 것처럼, 그것은 무모함이 아니라 하나님의 주권을 신뢰하는 믿음의 행동입니다.', E'오늘의 핵심\n바울은 성령의 경고와 동역자들의 눈물 어린 만류에도 불구하고, 주 예수의 이름을 위해 죽을 것까지 각오하며 예루살렘으로 향합니다.\n\n묵상 질문\n1. 사랑하는 사람들의 만류와 하나님의 부르심 사이에서 갈등할 때, 무엇을 기준으로 결정해야 할까요?\n2. 오해와 거짓 고발 속에서도 하나님은 어떻게 바울을 보호하시고 그분의 계획을 이루어 가셨나요?\n3. 내가 주님의 이름을 위해 감당해야 할 희생이나 고난은 무엇인지 기도해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-29', E'마지막 예루살렘 방문 (사도행전 22장)', E'사도행전 22장', E'예루살렘 성전 뜰에서 체포된 바울이 로마 군대의 영문 계단에 서서 군중을 향해 자신의 이야기를 풀어놓습니다. 히브리어로 말을 시작하자 소란하던 군중이 조용해집니다. 바울은 자신이 철저한 유대인이었음을 먼저 밝힙니다. 다소에서 태어났지만 예루살렘에서 자랐고, 당대 최고의 율법학자 가말리엘 문하에서 수학했으며, 그들과 같은 열심으로 하나님을 섬겼다고 말합니다. 그 열심이 얼마나 컸던지 그리스도인들을 박해하여 죽이기까지 했고, 남녀를 가리지 않고 결박하여 옥에 넘겼습니다.\n\n그러나 다메섹으로 가는 길에서 모든 것이 바뀌었습니다. 정오의 태양보다 밝은 빛이 그를 둘러 비추었고, "사울아 사울아 네가 왜 나를 박해하느냐"는 음성이 들렸습니다. 그 음성의 주인은 바로 그가 박해하던 나사렛 예수였습니다. 이 만남은 바울의 삶을 완전히 뒤집어 놓았습니다. 박해자에서 증인으로, 율법의 수호자에서 복음의 전파자로 변화된 것입니다.\n\n바울의 변화는 단순한 종교적 전향이 아니었습니다. 하나님께서는 아나니아를 통해 바울에게 분명한 사명을 주셨습니다. "네가 그를 위하여 모든 사람 앞에서 네가 보고 들은 것에 증인이 되리라"(행 22:15). 더 나아가 예루살렘 성전에서 기도하던 중 환상을 통해 이방인의 사도로 부르심을 받았습니다. 바울이 과거 자신의 잘못을 고백하며 주저할 때, 주님은 단호하게 "떠나가라 내가 너를 멀리 이방인에게로 보내리라"고 명하셨습니다.\n\n이방인 선교라는 말이 나오자 군중은 다시 격분합니다. 그들에게 이방인과 유대인이 하나님 앞에 동등하다는 것은 받아들일 수 없는 신성모독이었습니다. 소동이 커지자 천부장은 바울을 영내로 끌고 가 채찍질하며 심문하려 했습니다. 그러나 바울이 로마 시민임을 밝히자 상황은 급변합니다. 로마법은 시민권자를 재판 없이 형벌에 처하는 것을 엄격히 금했기 때문입니다.\n\n바울의 증언은 복음이 민족과 신분의 장벽을 넘어선다는 것을 보여줍니다. 철저한 유대주의자였던 그가 이방인의 사도가 되었고, 로마 시민권이라는 세상의 특권도 복음 전파를 위한 도구로 사용되었습니다. 하나님의 구원 계획은 인간의 편견과 제도를 뛰어넘어 모든 민족에게 열려 있음을 바울의 삶이 증거하고 있습니다.', E'오늘의 핵심\n바울은 자신의 극적인 회심 경험을 통해 복음이 유대인과 이방인 모두를 위한 것임을 증거하며, 하나님께서는 바울의 로마 시민권까지도 복음 전파의 도구로 사용하십니다.\n\n묵상 질문\n1. 바울처럼 과거의 열심이 잘못된 방향이었음을 깨달은 경험이 있나요? 하나님은 그것을 어떻게 바로잡아 주셨나요?\n2. 내가 가진 신분이나 배경, 특권을 하나님 나라를 위해 어떻게 사용할 수 있을까요?\n3. 복음을 전할 때 상대방의 언어와 문화를 이해하려는 노력을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-09-30', E'마지막 예루살렘 방문 (사도행전 23장)', E'사도행전 23장', E'공회 앞에 선 바울의 모습은 예상치 못한 전개로 이어집니다. "범사에 양심을 따라 하나님을 섬겼노라"는 그의 고백에 대제사장 아나니아는 바울의 입을 치라고 명령합니다. 이에 바울은 "회칠한 담이여 하나님이 너를 치시리로다"라고 맞섭니다. 대제사장을 욕했다는 지적에 바울은 즉시 사과하며 성경 말씀을 인용합니다. 이 장면은 바울이 얼마나 철저하게 말씀에 순종하려 했는지를 보여줍니다.\n\n그러나 바울의 지혜는 여기서 더욱 빛을 발합니다. 공회가 사두개인과 바리새인으로 나뉘어 있음을 간파한 바울은 "죽은 자의 소망 곧 부활로 말미암아 내가 심문을 받노라"고 외칩니다. 이 한마디로 공회는 둘로 갈라졌고, 바리새인들 중 일부는 오히려 바울을 옹호하기 시작합니다. 신학적 진리를 활용한 바울의 지혜로운 대처는 위기의 순간을 모면하는 계기가 되었습니다.\n\n큰 분쟁으로 바울이 찢겨질 위기에 처하자 로마 천부장이 그를 구출해 영내로 데려갑니다. 그날 밤, 주님께서 바울 곁에 서서 말씀하십니다. "담대하라 네가 예루살렘에서 나의 일을 증언한 것 같이 로마에서도 증언하여야 하리라"(행 23:11). 사람들의 계략과 위협 속에서도 하나님의 계획은 흔들림이 없었습니다.\n\n다음 날 사십여 명의 유대인들이 바울을 죽이기 전에는 먹지도 마시지도 않겠다며 맹세합니다. 그러나 하나님은 바울의 생질을 통해 이 음모를 드러내시고, 로마 천부장은 즉시 대응합니다. 이백 명의 보병과 칠십 명의 기병, 그리고 이백 명의 창병이 바울 한 사람을 호송하게 됩니다. 로마 시민권자를 보호하는 로마법의 위력이었지만, 그 배후에는 로마에서도 복음을 증언해야 할 바울을 지키시는 하나님의 섭리가 있었습니다.\n\n천부장 글라우디오 루시아가 총독 벨릭스에게 보낸 편지는 바울에게 죽이거나 결박할 만한 죄가 없다고 명시합니다. 종교적 논쟁으로 시작된 고발이 정치적 사건이 되었고, 이제 바울은 더 높은 권력 앞에서 복음을 증언할 기회를 얻게 됩니다. 가이사랴로 향하는 바울의 여정은 결국 로마로 가는 길의 시작이었습니다. 하나님은 인간의 악한 계략조차도 당신의 선한 목적을 이루는 도구로 사용하십니다.', E'오늘의 핵심\n극심한 위협 속에서도 하나님은 바울 곁에 서서 위로하시며, 로마에서의 증언이라는 더 큰 사명을 확증해 주셨습니다.\n\n묵상 질문\n1. 위기의 순간에 지혜롭게 대처한 바울처럼, 나는 어떻게 믿음과 지혜를 균형 있게 사용할 수 있을까요?\n2. 사십 명의 맹세도 막지 못한 하나님의 계획을 보며, 내 삶을 향한 하나님의 주권을 어떻게 신뢰할 수 있을까요?\n3. "담대하라"는 주님의 음성이 오늘 내게 필요한 상황은 무엇이며, 어떻게 응답할 수 있을까요?');
